        CARRY_THE_MARK_OF_THE_CRIMSON_LION_WITH                               = 7083,  -- Carry the mark of the crimson lion with pride!
        MAY_THE_FLAMES_OF_FREEDOM_BURN_FOR_ETERNITY                           = 7084,  -- May the flames of freedom burn for eternity!
        LET_THE_KNOWLEDGE_OF_THE_STAR_SIBYL_GUIDE                             = 7085,  -- Let the knowledge of the Star Sibyl guide you to victory!
        YOU_ARE_NOW_PARTICIPATING_IN_THE_ALLIED_CAMPAIGN                      = 7086,  -- You are now participating in the Allied Campaign.
        GREETINGS_I_AM_OF_THE_SAN_D_ORIAN                                     = 7087,  -- Greetings. I am of the San d'Orian Provincial Knights.
        GREETINGS_I_AM_OF_THE_BASTOKAN_LEGION                                 = 7088,  -- Greetings. I am of the Bastokan Legion.
        GREETINGS_I_AM_OF_THE_FEDERATION_OF_WINDURST                          = 7089,  -- Greetings. I am of the Federation of Windurst.
        GREETINGS_I_AM_CAMPAIGN_ARBITER_FOR_THE_ALLIED_2                      = 7090,  -- Greetings. I am , Campaign Arbiter for the Allied Forces.
        WHAT_CAN_I_HELP_YOU_WITH_NOTHING_PERFORMANCE                          = 7091,  -- What can I help you with? Nothing. Performance assessment. New Allied Tags. Temporary items. Union registration. Teleportation. Information on the Allied Campaign.
        WHAT_WOULD_YOU_LIKE_TO_KNOW_NOTHING_I                                 = 7092,  -- What would you like to know? Nothing. I'm sorry. About performance assessment. About Allied Tags. About temporary items. About Unions.
        I_AM_SORRY_BUT_AT_THIS_TIME_I                                         = 7093,  -- I am sorry, but at this time, I cannot be of any assistance in that area.
        UNDERSTOOD_I_SHALL_NOW_JUDGE_YOUR_PERFORMANCE_AND                     = 7094,  -- Understood. I shall now judge your performance and award the proper remuneration.
        AH_I_M_SORRY_TO_INFORM_YOU_THAT                                       = 7095,  -- Ah, I'm sorry to inform you that your performance has not earned you any compensation.
        UNDERSTOOD_I_SHALL_PREPARE_A_NEW_SET_OF                               = 7096,  -- Understood. I shall prepare a new set of tags for you now.
        YOU_VE_ALREADY_UNDERGONE_AN_EVALUATION_FOR_THIS                       = 7097,  -- You've already undergone an evaluation for this battle, or had you forgotten? As much as I'd like to, I'm forbidden from providing you with a new set of Allied Taegs until the next battle begins.
        ANYONE_WEARING_ALLIED_TAGS_WHILE_PARTICIPATING_IN_A                   = 7098,  -- Anyone wearing Allied Tags while participating in a campaign battle will be judged on their overall performance.
        SOLDIERS_WILL_BE_EVALUATED_NOT_ONLY_ON_THEIR                          = 7099,  -- Soldiers will be evaluated not only on their fighting skills, but also on how much they contribute to the efforts of their allies through means such as healing and enhancing.
        HOWEVER_BEWARE_THAT_IF_YOU_LEAVE_THE_AREA                             = 7100,  -- However, beware that if you leave the area before being assessed, you will be deemed a deserter and will forfeit all rewards earned that day.
        ALSO_WHILE_THERE_ARE_NO_IMMEDIATE_PENALTIES_FOR                       = 7101,  -- Also, while there are no immediate penalties for being knocked out, falling in battle will significantly lower the score given to you.
        WHEN_YOU_ARE_READY_TO_RECEIVE_COMPENSATION_FOR                        = 7102,  -- When you are ready to receive compensation for your work on the field, return to me and I shall assess your performance and provide you with your payment.
        ALLIED_TAGS_ARE_A_SPECIAL_TYPE_OF_IDENTIFICATION                      = 7103,  -- Allied Tags are a special type of identification given to all participants of Allied Campaign battles.
        THERE_ARE_BENEFITS_AS_WELL_AS_DRAWBACKS_TO                            = 7104,  -- There are benefits, as well as drawbacks, to wearing the tags. One of the benefits is that in the case you are knocked out on the battlefield, you will not lose any experience points.
        HOWEVER_SOME_OF_THE_DRAWBACKS_INCLUDE_THE_INABILITY                   = 7105,  -- However, some of the drawbacks include the inability to improve skills and earn experience points for individual kills, as well as the right to loot fallen enemies.
        TEMPORARY_ITEMS_CAN_BE_PURCHASED_IN_EXCHANGE_FOR                      = 7106,  -- Temporary items can be purchased in exchange for Allied Notes.
        THERE_ARE_SEVERAL_DIFFERENT_VARIETIES_OF_ITEMS_BUT                    = 7107,  -- There are several different varieties of items, but they all have one thing in common--they can only be used on the battlefield they were issued.
        IT_IS_HIGHLY_RECOMMENDED_THAT_YOU_FIRST_SURVEY                        = 7108,  -- It is highly recommended that you first survey a battle's conditions and then select the supplies that you believe will benefit you most.
        PLEASE_REMEMBER_THAT_ALL_TEMPORARY_ITEMS_YOU_CARRY                    = 7109,  -- Please remember that all temporary items you carry on your person will be confiscated in the event that you leave the area.
        YOU_CAN_ONLY_PURCHASE_TEMPORARY_ITEMS_IF_YOUR                         = 7110,  -- You can only purchase temporary items if your nation of allegiance is commanding the campaign.
