        DON_T_HURT_POOR_GELTPIX_GELTPIX_S_JUST                                = 7118,  -- Don't hurt poor Geltpix! Geltpix's just a merchant from Boodlix's Emporium in Jeuno. Kingdom vendors don't like gil, but Boodlix knows true value of new money.
        BLINGBRIX_GOOD_GOBBIE_FROM_BOODLIX_S_BOODLIX_S                        = 7119,  -- Blingbrix good Gobbie from Boodlix's! Boodlix's Emporium help fighting fighters and maging mages. Gil okay, okay?
        BOODLIX_S_EMPORIUM_OPEN_FOR_BUSINESS_BOODLIX_S                        = 7120,  -- Boodlix's Emporium open for business! Boodlix's gots whats you wants, at the price yous likes! It's okay, we takes yours gils, too!
        HEH_HEH_HEH_NO_SHOOT_NO_SLICE_DIBSTIX                                 = 7121,  -- Heh heh heh! No shoot! No slice! Dibstix good Gobbie. Good Gobbie from Boodlix's Emporium sell you goodies, yeah? Gil okay. Gil okay!
        LOLLYSPOX_BE_BEASTMAN_BUT_LOLLYSPOX_LOVE_ALTANA_ALTANA                = 7122,  -- Lollyspox be beastman, but Lollyspox love Altana. Altana make Lollyspox rich with sparklies from heavens. You make me rich, too?
        MIGHT_YOU_BE_A_STUDENT_OF_THE_SAME                                    = 7123,  -- Might you be a student of the same field as I? If that is the case, I might be able to provide you with the proper grimoires...at a price, of course.
        SPONDULIX_COMES_ALL_THE_WAY_FROM_BOODLIX_S                            = 7124,  -- Spondulix comes all the way from Boodlix's Emporium to help Tarutaru and Mithra. I can help you, too! You have gil, no?
