        I_M_A_MOOGLE_WE_MOOGLES_LIKE_TAKING                                   = 7307,  -- I'm a moogle! We moogles like taking care of houses and items! Nice to meet you, kupo!
        I_LL_TELL_YOU_ALL_ABOUT_YOUR_MOG                                      = 7308,  -- I'll tell you all about your Mog House, kupo!
        FIRST_THE_BASICS_KUPO_OPEN_YOUR_MAIN_MENU                             = 7309,  -- First, the basics, kupo! Open your main menu, Master. The button at the very bottom changes to Mog House when you're in your Mog House, kupo!
