        BAH_WERE_IT_MY_DECISION_YOU_D_NOT                                     = 7616,  -- Bah! Were it my decision, you'd not have seen it again until you were a man grown. You have the generosity of this stranger here to thank.
        OH_YOU_TRULY_ARE_TOO_KIND_MILORD_MILADY                               = 7617,  -- Oh, you truly are too kind! Milord/Milady], ah...
        THANK_YOU_MILORD_MILADY                                               = 7618,  -- Thank you, Milord/Milady] %!
        WELL_NOW_THAT_YOU_HAVE_A_BLADE_AGAIN                                  = 7619,  -- Well, now that you have a blade again, I suppose I must teach you to swing it without lopping off your own extremities.
        TRULY_ON_MY_HONOR_FATHER_I_SHAN_T                                     = 7620,  -- Truly? On my honor, Father, I shan't let you down!
        OHO_THERE_S_A_SPIRITED_REPLY_I_JUST                                   = 7621,  -- Oho! There's a spirited reply. I just might make a knight of you yet!
        HAIL_EXOROCHE_WHAT_A_CHARMING_LITTLE_YOU_HAVE                         = 7622,  -- Hail, Exoroche! What a charming little % you have there. A fitting toy for a child such as yourself, methinks.
        ME_I_VE_ALREADY_RECEIVED_A_XIPHOS_FROM                                = 7623,  -- Me, I've already received a xiphos from my father. A true knight's weapon, you see.
        PERHAPS_WE_CAN_SPAR_SOMETIME_SHOULD_YOU_EVER                          = 7624,  -- Perhaps we can spar sometime. Should you ever feel the need for a proper bruising, that is! Hahaha!
        SNIFF_F_FATHER                                                        = 7625,  -- <Sniff>... F-Father...
        HEAR_ME_WELL_EXOROCHE                                                 = 7626,  -- Hear me well, Exoroche.
        LET_OTHERS_SAY_AS_THEY_WILL                                           = 7627,  -- Let others say as they will.
        IN_THE_END_TIS_NOT_THE_MIGHTIEST_SWORD                                = 7628,  -- In the end, 'tis not the mightiest sword, nor even the savviest fencer who shall win the day. It is the one with honor and justice on his side.
        REMEMBER_THIS_ALWAYS_DISCIPLINE_YOURSELF_IN_MIND_AND                  = 7629,  -- Remember this always, discipline yourself in mind and body, and you will grow strong.
        YES_FATHER_ONE_DAY_I_SHALL_BE_THE                                     = 7630,  -- Yes, Father! One day, I shall be the strongest, bravest knight in the Kingdom! I will make you proud!
        I_VE_NOT_FELT_SUCH_A_CLOSE_BOND                                       = 7631,  -- I've not felt such a close bond with my son in quite some time. I am in your debt, %.
        AS_IT_SEEMS_THE_LAD_WILL_HAVE_NEED                                    = 7632,  -- As it seems the lad will have need of his % after all, pray accept this instead as a token of my gratitude.
        THE_BOY_MAY_BE_TENDER_IN_YEARS_BUT                                    = 7633,  -- The boy may be tender in years, but his heart is true. I shall endeavor to see him raised to be as strong and honorable as yourself.
        I_MAY_HAVE_NEITHER_THE_STRONGEST_ARM_NOR                              = 7634,  -- I may have neither the strongest arm nor the sharpest blade, but I shall always fight for honor and justice!
