        THIS_IS_WATCHDOG_ALLEY_HAVE_YOU_COME_TO                               = 10803,  -- This is Watchdog Alley. Have you come to view the Orc prisoner?
        HE_S_RIGHT_OVER_THERE_THE_ROYAL_KNIGHTS                               = 10804,  -- He's right over there. The Royal Knights caught the fiend and threw him in a cage as a warning to his foul brethren.
        THIS_ORC_APPEARS_TO_SPEAK_OUR_LANGUAGE_SURPRISINGLY                   = 10805,  -- This Orc appears to speak our language surprisingly well. You may approach if you wish.
        BLAST_SOMEONE_S_COMING                                                = 10806,  -- (Blast... Someone's coming...)
        W_WAIT_WE_RE_NOT_DONE_HERE_DARVYLLE                                   = 10807,  -- W-wait! We're not done here, Darvylle!
        HM                                                                    = 10808,  -- Hm...?
        H_HELLO_KIND_STRANGER_LISTEN_TO_MY_TALE                               = 10809,  -- H-hello, kind stranger! Listen to my tale...if it please you!
        I_UNDERSTAND_THAT_YOU_MAY_BE_LOATH_TO                                 = 10810,  -- I understand that you may be loath to believe one in my situation...
        BUT_I_AM_IN_ACTUAL_FACT_AN_ELVAAN                                     = 10811,  -- But I am, in actual fact, an Elvaan--a descendant of House Aurchiat.
        THIS_UNLOVELY_FORM_IS_THE_RESULT_OF_A                                 = 10812,  -- This unlovely form is the result of a witch's curse.
        BEHOLD_THIS_SIGNET_RING_IT_BEARS_THE_COAT                             = 10813,  -- Behold this signet ring. It bears the coat of arms of House Aurchiat, and is all I retain of my identity.
        THE_SYMBOL_OF_A_UNICORN_ADORNS_THE_RING                               = 10814,  -- The symbol of a unicorn adorns the ring.
        THE_TEMPLE_KNIGHT_HERE_BEFORE_YOU_WAS_THE                             = 10815,  -- The Temple Knight here before you was the merciful Sir Darvylle. He chose to believe my tale.
        HE_ALSO_CHOSE_TO_LEAVE_ME_WITH_A                                      = 10816,  -- He also chose to leave me with a ring of keys--including the one to this cage.
        WITHOUT_A_THOUGHT_FOR_HIS_OWN_POSITION_SIR                            = 10817,  -- Without a thought for his own position, Sir Darvylle is graciously allowing me one last look at the faces of my beloved family...
        I_COULD_NOT_LET_FEAR_MAKE_A_MOCKERY                                   = 10818,  -- I could not let fear make a mockery of his generosity.
        YET_WHEN_I_STRETCHED_OUT_A_HAND_TO                                    = 10819,  -- Yet when I stretched out a hand to work the lock on the outside of the cage, I was stymied...
        THESE_CURSED_ORC_ARMS_ARE_AS_THICK_AS                                 = 10820,  -- These cursed Orc arms are as thick as table hams! I could not fit my limbs through the bars!
        UGH                                                                   = 10821,  -- Ugh...
        I_PROMISE_NOT_TO_FLEE_WILL_YOU_NOT                                    = 10822,  -- I promise not to flee. Will you not open the cage in my stead?
        OPEN_THE_CAGE_GIVE_ME_THE_KEYS_THEN                                   = 10823,  -- Open the cage? Give me the keys, then. Nice try.
        MY_DEAR_WIFE_AND_DOTING_CHILD_ABIDE_IN                                = 10824,  -- My dear wife and doting child abide in my estate...
        IF_I_MIGHT_PEEK_IN_IF_ONLY_FROM                                       = 10825,  -- If I might peek in...if only from the shadows... I must see my family once more while my heart yet beats!
        THANK_YOU                                                             = 10826,  -- Thank you!
        I_SHALL_RETURN_THE_KEYS_MYSELF_I_CANNOT                               = 10827,  -- I shall return the keys myself. I cannot have the guards believing you aided in my escape.
        NOW_I_MUST_AWAY_BEFORE_THE_ALARM_IS                                   = 10828,  -- Now I must away before the alarm is raised.
        BLESSED_CHILD_OF_ALTANA_IF_ONLY_I_COULD                               = 10829,  -- Blessed child of Altana! If only I could meet you as my true self!
        HAVE_A_NICE_CONVERSATION_WITH_OUR_ORCISH_GUEST                        = 10830,  -- Have a nice conversation with our Orcish guest? Where did he learn to speak so eloquently, I wonder...
        THAT_CHATTY_ORC_HAS_ESCAPED                                           = 10831,  -- That chatty Orc has escaped!
        BUT_NOT_BEFORE_RELEASING_ALL_THE_OTHER_PRISONERS                      = 10832,  -- But not before releasing all the other prisoners...
        THERE_IS_EVIDENCE_AT_THE_SCENE_THAT_THE                               = 10833,  -- There is evidence at the scene that the Orc was supplied with %. We have a traitor in our midst.
        THE_ESCAPE_WAS_NOTICED_AFTER_THE_CHANGING_OF                          = 10834,  -- The escape was noticed after the changing of the guard. Could this have happened during my watch...?
        WE_HAVE_EVERY_ABLE_BODIED_TEMPLE_KNIGHT_AVAILABLE                     = 10835,  -- We have every able-bodied Temple Knight available assigned to the search, but...hm?
        IF_THE_KNIGHTS_CHOOSE_TO_DO_NOTHING_THEN                              = 10836,  -- If the knights choose to do nothing, then the Young Griffons will take matters into their own hands!
        EXCENMILLE_LEAVE_MILITARY_MATTERS_TO_YOUR_ELDERS_NOW                  = 10837,  -- Excenmille... Leave military matters to your elders. Now, return home and cease this unseemly conduct.
        ID_10838                                                              = 10838,  -- ...!!!
        THAT_IS_YOUR_ANSWER_TO_EVERYTHING_FATHER_IT                           = 10839,  -- That is your answer to everything, Father! It is the same tired answer you gave when--
        EXCENMILLE                                                            = 10840,  -- Excenmille!
        RAHAL_WHAT_IS_AFOOT                                                   = 10841,  -- Rahal. What is afoot?
        BISTILLOT_S_WORK_IS_COMPLETE                                          = 10842,  -- Bistillot's work is complete!
        TRULY                                                                 = 10843,  -- Truly!?
        YES_WE_MUST_MAKE_HASTE_TO_THE_MEETING                                 = 10844,  -- Yes! We must make haste to the meeting place.
        IT_SHALL_BE_THE_YOUNG_GRIFFONS_WHO_END                                = 10845,  -- It shall be the Young Griffons who end this war! The elders of this kingdom couldn't be trusted to lace their own boots!
        WHO_IS_THAT_YOU_ASK_THAT_MY_FRIEND                                    = 10846,  -- Who is that, you ask? That, my friend, is Count Alphonimile M Aurchiat, a Royal Knight and lord of the territory of Norvallen.
        I_HAVE_ONLY_MYSELF_TO_BLAME_FOR_THE                                   = 10847,  -- I have only myself to blame for the behavior of my son and heir...
        EVER_SINCE_THE_INCIDENT_WHEN_THE_BLOODWING_HORDE                      = 10848,  -- Ever since the incident when the Bloodwing Horde enclosed the capital in their merciless grip, the streets have grown increasingly dangerous.
        OUR_HIGH_RANKING_KNIGHTS_ARE_BEING_TARGETED_BY                        = 10849,  -- Our high-ranking knights are being targeted by Tonberry assassins. Why, General Mouchand of the Temple Knights was slain not three days ago.
        AND_NOW_WE_HAVE_THIS_INCIDENT_WITH_PRISONERS                          = 10850,  -- And now we have this incident with prisoners running free. The security of San d'Oria is compromised. We must all be on our guard.
        THE_COUNT_HAS_NOT_HAD_TIME_TO_REST                                    = 10851,  -- The count has not had time to rest since the Battle of Jugner.
        IF_HE_HAD_BUT_MOBILIZED_A_LARGER_FORCE                                = 10852,  -- If he had but mobilized a larger force during that battle, the Knights of Norvallen might still be with us today...
        AND_WITH_THE_LOSS_OF_GENERAL_MOUCHAND_COUNT                           = 10853,  -- And with the loss of General Mouchand, Count Aurchiat will have a hard time coordinating the actions of the Royal and Temple Knights.
        IT_ALSO_APPEARS_WE_FACE_A_CUNNING_ADVERSARY                           = 10854,  -- It also appears we face a cunning adversary in the Orcs, if that prison break is truly of their making.
        PERHAPS_THE_YOUNG_GRIFFONS_WILL_BECOME_OUR_LAST                       = 10855,  -- Perhaps the Young Griffons will become our last bastion of hope, after all... I jest, of course.
        WHO_ARE_THE_YOUNG_GRIFFONS_AH_MERELY_A                                = 10856,  -- Who are the Young Griffons? Ah, merely a name those enthusiastic youths have given to themselves.
        THEY_EMPLOY_THE_SMALL_COURTYARD_FURTHER_INTO_WATCHDOG                 = 10857,  -- They employ the small courtyard further into Watchdog Alley as a meeting place. I hear they don't appreciate intrusions into their territory.
        COULD_THIS_PRISON_BREAK_HAVE_HAPPENED_DURING_MY                       = 10858,  -- Could this prison break have happened during my watch...?
        THE_SMALL_COURTYARD_FURTHER_INTO_WATCHDOG_ALLEY_IS                    = 10859,  -- The small courtyard further into Watchdog Alley is a meeting place for a group of young, would-be knights. I hear they don't appreciate intrusions into their territory.
        THE_SMALL_COURTYARD_FURTHER_INTO_WATCHDOG_ALLEY_IS_2                  = 10860,  -- The small courtyard further into Watchdog Alley is a meeting place for a group of young, would-be knights.
        I_SHALL_PASS_ON_TO_YOU_ANY_INFORMATION                                = 10861,  -- I shall pass on to you any information we receive regarding the escape. You have spoken with the cur, and may have a better chance of understanding how he thinks.
        HOLD_WHERE_YOU_ARE_INTRUDER_THIS_IS_THE                               = 10862,  -- Hold where you are, intruder! This is the territory of the Young Griffons! State your business, or begone!
        DO_YOU_MIND_RHOLONT_YOU_RE_AWFULLY_LOUD                               = 10863,  -- Do you mind, Rholont? You're awfully loud, and it's very hard to concentrate...
        NOW_IF_I_PUSH_THIS_WHILE_TWISTING_THAT                                = 10864,  -- Now, if I push this while twisting that...
        TH_THE_CAPTAIN_AND_LIEUTENANT_HAVE_RETURNED                           = 10865,  -- Th-the captain and lieutenant have returned!
        YOUNG_GRIFFONS_FALL_IN                                                = 10866,  -- Young Griffons! Fall in!
        CAPTAIN_EXCENMILLE_LIEUTENANT_RAHAL_WELCOME_BACK_FROM_YOUR            = 10867,  -- Captain Excenmille! Lieutenant Rahal! Welcome back from your mission!
        AT_EASE_SENTINEL_RHOLONT                                              = 10868,  -- At ease, Sentinel Rholont.
        ENGINEER_BISTILLOT                                                    = 10869,  -- Engineer Bistillot!
        SOME_QUIET_IF_YOU_PLEASE_CAPTAIN                                      = 10870,  -- Some quiet, if you please, Captain.
        COME_OUT_OF_THERE_AND_LET_S_SEE                                       = 10871,  -- Come out of there and let's see this--
        EXCENMILLE_2                                                          = 10872,  -- Excenmille...
        HM_WHAT_IS_IT                                                         = 10873,  -- Hm? What is it?
        WE_HAVE_AN_INTRUDER                                                   = 10874,  -- We have an intruder.
        WHY_IS_THERE_AN_ELDER_HERE                                            = 10875,  -- Why is there an elder here!?
        SENTINEL_RHOLONT_YOU_HAVE_NOT_FORGOTTEN_THE_THIRD                     = 10876,  -- Sentinel Rholont! You have not forgotten the third rule, I trust?
        NO_SIR                                                                = 10877,  -- No, sir!
        THE_THIRD_RULE_OF_THE_YOUNG_GRIFFON_CHARTER                           = 10878,  -- The third rule of the Young Griffon charter states that no elder may be permitted entrance into our territory!
        THEN_WHY_HAVE_YOU_BEEN_REMISS_IN_YOUR                                 = 10879,  -- Then why have you been remiss in your duty!?
        YOU_THERE                                                             = 10880,  -- You there!
        I_KNOW_NOT_YOUR_BUSINESS_HERE_BUT_YOU                                 = 10881,  -- I know not your business here, but you are trespassing on Young Griffon land. Begone at once!
        CAPTAIN_EXCENMILLE                                                    = 10882,  -- Captain Excenmille!
        NOW_WHAT                                                              = 10883,  -- Now what!?
        ROYAL_SQUIRE_ALTENNIA_APPROACHES                                      = 10884,  -- Royal Squire Altennia approaches!
        WELL_WELL_ARE_WE_ALL_PLAYING_NICELY_TOGETHER                          = 10885,  -- Well, well. Are we all playing nicely together?
        YOUR_VIGILANCE_IS_TO_BE_COMMENDED_SENTINEL_RHOLONT                    = 10886,  -- Your vigilance is to be commended, Sentinel Rholont.
