        GREETINGS_I_AM_CURATE_PALARDAIFAUT_AND_I_HAVE                         = 11154,  -- Greetings, I am Curate Palardaifaut, and I have been assigned to the Knights of the Iron Ram to ensure that its members stray not from the path of the Goddess.
        BOWS_DEEPLY                                                           = 11155,  -- % bows deeply.
        ONE_OF_MY_MANY_DUTIES_ENTAILS_LENDING_AN                              = 11156,  -- One of my many duties entails lending an ear to the grievances of my brave brothers and sisters.
        MIGHT_THERE_BE_SOMETHING_TROUBLING_YOU                                = 11157,  -- Might there be something troubling you, %?
        I_HAVE_AN_OPINION_REGARDING_PRIVACY_ISSUES_OUR                        = 11158,  -- I have an opinion regarding: Privacy issues. Our commanders. Our battle strategies. Our internal policies. Nothing.
        WORRY_NOT_MY_CHILD_YOUR_NAME_WILL_BE                                  = 11159,  -- Worry not, my child. Your name will be revealed to no one.
        FEEL_FREE_TO_EXPRESS_WHATEVER_FEELINGS_YOU_MAY                        = 11160,  -- Feel free to express whatever feelings you may have, without fear of future reprisal.
        HOWEVER_THIS_DOES_NOT_NECESSARILY_GUARANTEE_YOUR_WISHES               = 11161,  -- However, this does not necessarily guarantee your wishes will be granted.
        WHILE_THE_ROYAULAIS_MAKES_IT_A_POINT_TO                               = 11162,  -- While the royaulais makes it a point to consider the opinions of his subjects, the final decision regarding whether or not to implement a new course of action lies solely with His Highness.
        I_SEE_I_HAVE_RECORDED_YOUR_WORDS_AND                                  = 11163,  -- I see... I have recorded your words and shall present them to the royaulais himself.
        UNDERSTOOD_HOWEVER_IF_YOU_EVER_WISH_TO_MAKE                           = 11164,  -- Understood. However, if you ever wish to make your voice heard, speak with me.
        AND_SHOULD_A_SHROUD_OF_DARKNESS_VEIL_THE                              = 11165,  -- And should a shroud of darkness veil the Light of dawn, the undying hope in mine heart would guideth me through the abyss to the Promised--
        AH_MY_APOLOGIES_WAYWARD_LAMB_BUT_I_HAVE                               = 11166,  -- Ah, my apologies, wayward lamb, but I have not yet finished my daily prayer. Please, allow me to concentrate, lest I offend the Goddess with wildering driveling.
        AH_OUR_FINE_GENERALS                                                  = 11167,  -- Ah, our fine generals.
        A_LEADER_OF_MEN_IS_ONLY_AS_STRONG                                     = 11168,  -- A leader of men is only as strong as the trust placed upon him by his followers. His Majesty would do well to know who among his commanders has earned the respect of the people.
        TELL_ME_WHICH_GENERAL_YOU_BELIEVE_THE_MOST                            = 11169,  -- %, tell me which general you believe the most competent.
        WHO_WOULD_YOU_FOLLOW_TO_DEATH_ROYAL_GUARD                             = 11170,  -- Who would you follow to death? Royal Guard General Davilles. Royal Knight General Cousseraux. Temple Knight General Brunnaut. Provincial Knight General Rouhent. Provincial Knight General Virgaut. Reserve Knight General Leonoyne. I require more time to consider.
        AH_VALAINERAL_R_DAVILLES_HEIR_TO_THE_DAVILLES                         = 11171,  -- Ah, Valaineral R Davilles, heir to the Davilles line. Known by many for his warm personality, this master of the blade is said to transform into a beast when on the battlefield.
        AH_LORD_YRVAULAIR_S_COUSSERAUX_THE_YEARS_HAVE                         = 11172,  -- Ah, Lord Yrvaulair S Cousseraux--the years have taken little from this expert tactician. Specializing in sieges, the brave general excels when faced with a fortress in need of breaching.
        AH_CARDINAL_FEBRENARD_C_BRUNNAUT_STRIVING_HARD_DAY                    = 11173,  -- Ah, Cardinal Febrenard C Brunnaut... Striving hard day and night to maintain peace within the walls of the capital. While the youngest of our nation's generals, he is often the most composed.
        AH_LORD_ROUHENT_OF_THE_KNIGHTS_OF_NORVALLEN                           = 11174,  -- Ah, Lord Rouhent of the Knights of Norvallen--a hero amongst men, known for putting the needs of his knights before all else. Missions of reprovisioning are among his specialties.
        AH_LADY_VIRGAUT_OF_THE_KNIGHTS_OF_ARAGONEU                            = 11175,  -- Ah, Lady Virgaut of the Knights of Aragoneu. Let not her pulchritudinous visage fool you, for she is perhaps one of the finest generals in the Kingdom. Her scouts' ability to gather intelligence on the enemy, combined with her ability to apply that knowledge to constructing precise battle tactics, is known across Vana'diel.
        AH_SIR_LEONOYNE_OF_THE_KNIGHTS_OF_THE                                 = 11176,  -- Ah, Sir Leonoyne of the Knights of the Savage Hound--a cold-blooded warrior who earned his nobility after a showing of unmatched bravery on the battlefield. Highly regarded by the royaulais, his ruthless methods strike fear into those beastmen who dare challenge his knights.
        DO_YOU_BELIEVE_HE_IS_OUR_KINGDOM_S                                    = 11179,  -- Do you believe he is our Kingdom's top general?
        HE_IS_THE_BEST_WE_HAVE                                                = 11180,  -- He is... The best we have! ...
        INTERESTING                                                           = 11181,  -- Interesting...
        WAIT_ONE_MOMENT                                                       = 11182,  -- Wait one moment...
        I_SEEM_TO_RECALL_YOU_RECENTLY_STATING_WAS                             = 11183,  -- I seem to recall you recently stating [Royal Guard General Davilles/Royal Knight General Cousseraux/Temple Knight General Brunnaut/General Feldrautte I Rouhent/General Cerane I Virgaut/Reserve Knight General Leonoyne] was our most reliant leader.
        SO_YOU_FEEL_THERE_MAY_BE_SOMETHING_AMISS                              = 11184,  -- So you feel there may be something amiss with our nation's current battle strategy.
        WHICH_PATH_DO_YOU_FEEL_WOULD_BENEFIT_US                               = 11185,  -- Which path do you feel would benefit us most?
        WHICH_DO_YOU_SUGGEST_A_PREEMPTIVE_STRIKE_DIVERSIONARY                 = 11186,  -- Which do you suggest? A preemptive strike. Diversionary tactics. Battleline preservation. Stronghold defenses. Troop conditioning. Troop training. Reconnaissance. Sabotage. Nothing.
        QUITE_AN_AGGRESSIVE_TACTIC_ON_THE_OTHER_HAND                          = 11187,  -- Quite an aggressive tactic... On the other hand, a preemptive strike can be the quickest way to bring new regions under San d'Orian control, even if it results in heavier losses.
        QUITE_A_DEVIOUS_TACTIC_DEPLOYING_A_SMALL_UNIT                         = 11188,  -- Quite a devious tactic... Deploying a small unit of elite forces to distract the enemy while another cuts off vital supply lines... Brilliant!
        AH_A_WISE_TACTIC_REINFORCE_DEFENSES_IN_ORDER                          = 11189,  -- Ah, a wise tactic... Reinforce defenses in order to maintain battlelines, thus gradually draining the enemy of its influence.
        AH_A_SOUND_TACTIC_REINFORCE_STRONGHOLD_DEFENSES_IN                    = 11190,  -- Ah, a sound tactic... Reinforce stronghold defenses in order to prevent enemy ambushes and stabilize supply routes.
