        AH_NEVER_MIND_FORGET_YOU_HEARD_ANYTHING_FROM                          = 11240,  -- Ah, never mind. Forget you heard anything from me.
        WHAT_THE_HELL_IS_THIS_DO_I_LOOK                                       = 11241,  -- What the hell is this? Do I look like a goldsmith? Get that thing out of my face!
        HAH_YOU_THINK_YOU_CAN_BUY_MY_LOYALTY                                  = 11242,  -- Hah! You think you can buy my loyalty with a single throwing star!?
        HMPH_I_MIGHT_CONSIDER_HELPING_OUT_BUT_I                               = 11243,  -- Hmph... I might consider helping out [your kingdom/your republic/your federation], but I won't be making you any promises.
        HMPH_I_LL_CONSIDER_REMAINING_WITH_BUT_I                               = 11244,  -- Hmph... I'll consider remaining with [your kingdom/your republic/your federation], but I won't make you any guarantees.
        AS_YOU_CAN_SEE_I_STILL_HAVE_MANY                                      = 11245,  -- As you can see, I still have many malms to tread before my training is complete. Perhaps one day our paths will cross again on the fields of battle. Until then, friend.
