        THIS_OPERATION_REQUIRES_THAT_YOU_LOCATE_AND_REMOVE                    = 11638,  -- This operation requires that you locate and remove any hazardous objects located within San d'Oria's walls.
        THIS_OPERATION_REQUIRES_THAT_YOU_PATROL_SAN_D                         = 11639,  -- This operation requires that you patrol San d'Orian territory and eliminate any immediate threats to the Kingdom.
