        RYAAAAAAAAAH                                                          = 11799,  -- Ryaaaaaaaaah!
        MEN_DO_NOT_FEAR_THE_ENEMY_IT_IS                                       = 11800,  -- Men! Do not fear the enemy! It is our blades they shall fear!
        A_SWIFT_END_IS_THE_ONLY_MERCY_YOU                                     = 11801,  -- A swift end is the only mercy you will receive from me, fiends!
        WATCH_CAREFULLY_BECAUSE_THIS_IS_THE_LAST_THING                        = 11802,  -- Watch carefully, because this is the last thing you'll ever see in this life!
