        ARMY_FREELANCE_LEAVES_RESULT                                          = 11926,  -- [San d'Orian/Bastokan/Windurstian/Orcish/Quadav/Yagudo/Kindred]Army freelance # leaves. Result: [Victory/Defeat...]
