        THE_ALLIED_FORCES_OF_ALTANA_HAVE_RETREATED                            = 11937,  -- The Allied Forces of Altana have retreated...
        OBJECTIVE_COMPLETED_REPORT_TO_SIR_RASDINICE_IN_SOUTHERN               = 11938,  -- Objective completed. Report to Sir Rasdinice in Southern San d'Oria.
        OBJECTIVE_COMPLETED_REPORT_TO_FIRST_CENTURION_HIERONYMUS_IN           = 11939,  -- Objective completed. Report to First Centurion Hieronymus in the Bastok Markets.
        OBJECTIVE_COMPLETED_REPORT_TO_EMHI_TCHAORYO_IN_WINDURST               = 11940,  -- Objective completed. Report to Emhi Tchaoryo in Windurst Waters.
