        YOU_HAVE_BEEN_A_GREAT_HELP_THE_KNOWLEDGE_2                            = 12080,  -- You have been a great help, %! The knowledge you were able to pass on today will surely benefit our nation in its future endeavors.
        A_HERO_S_STORY_THE_DEEDS_OF_IN                                        = 12081,  -- %, a hero's story! The deeds of %, in all their gloryt
        A_TRAVELING_BARD_WALKS_FAR_AND_NEAR_WHILE                             = 12082,  -- A traveling bard walks far and near While wand'ring this celestial sphere From bustling towns to godforsaken lands. But none I love more than the swell Inhabitants of Vana'diel, Espec'lly when their gil comes to my hands.t
