        UNLOCK_WHICH_ACHIEVEMENT_NONE_JOB_LEVEL_SYNTHESIS_SKILL               = 12093,  -- Unlock which achievement? None. Job Level. Synthesis Skill 100. San d'Oria Rank 10. Bastok Rank 10. Windurst Rank 10. Zilart Missions. Promathia Missions. Aht Urhgan Missions. Mercenary Rank. %. %. %. %. %. %. %. %. %. %. %. %. View next page.
        UNLOCK_WHICH_ACHIEVEMENT_NONE_ARTIFACT_RELATED_QUESTS_GUILDWORKERS    = 12094,  -- Unlock which achievement? None. Artifact related Quests. Guildworkers' Union Entry. Wings of the Goddess Missions. Past Vana'diel Nation Quests. %. %. %. %. %. %. %. %. Support Jobs. Extra Jobs. %. %. %.
        UNLOCK_WHICH_ACHIEVEMENT_NONE_LEVEL_75_WARRIOR_LEVEL                  = 12095,  -- Unlock which achievement? None. Level 75 Warrior. Level 75 Monk. Level 75 White Mage. Level 75 Black Mage. Level 75 Red Mage. Level 75 Thief. Level 75 Paladin. Level 75 Dark Knight. Level 75 Beastmaster. Level 75 Bard. Level 75 Ranger. Level 75 Samurai. Level 75 Ninja. Level 75 Dragoon. Level 75 Summoner. Level 75 Blue Mage. Level 75 Corsair. Level 75 Puppetmaster. Level 75 Dancer. Level 75 Scholar.
        YOU_HAVE_NO_ACHIEVEMENTS_TO_UNLOCK                                    = 12096,  -- You have no achievements to unlock.
        I_AM_RONGELOUTS_COMMANDER_OF_THE_KNIGHTS_OF                           = 12097,  -- I am Rongelouts, commander of the Knights of the Iron Ram of the Royal Knights of San d'Oria. I shall personally set straight any cowards in our ranks. It would not be long before they would come to fear my sword more than beastman claw!
        WE_MUST_NOT_GIVE_IN_TO_FEAR_IN                                        = 12098,  -- We must not give in to fear in the face of the Beastman Confederate. I shall personally set straight any cowards in our ranks. It would not be long before they would come to fear my sword more than beastman claw!
        THAT_SHOP_HAS_CLOSED_DOWN_THE_OWNER_WENT                              = 12099,  -- That shop has closed down. The owner went missing right after the war broke out. Shame, too. He was such a nice fellow.
        TROUPE_MAYAKOV_HAS_HAD_THE_ENTIRE_LION_SPRINGS                        = 12100,  -- Troupe Mayakov has had the entire Lion Springs Tavern rented out for rehearsals. There's been a near constant stream of dancers going in and out recently. Unmistakable bunch, them.
        HEY_YOU_WHADDAYA_SAY_TO_A_LITTLE_FRIENDLY                             = 12101,  -- Hey you, whaddaya say to a little friendly wager? The Allied Forces of Altana or the Beastman Confederate? Where's your money?
        HAHA_I_M_SORRY_I_M_SORRY_NEVER                                        = 12102,  -- Haha, I'm sorry, I'm sorry. Never mind me.
        SUCH_A_GRUESOME_SCENE_WHO_WOULD_HAVE_THOUGHT                          = 12103,  -- Such a gruesome scene... Who would have thought monsters like that existed in this world?
        OUT_OF_NOWHERE_AN_ENORMOUS_WORM_ROSE_UP                               = 12104,  -- Out of nowhere, an enormous worm rose up from the belly of the earth itself. With its huge mouth it effortlessly swallowed up a number of nearby soldiers, who were helpless to react.
        EVEN_IF_THE_CITY_IS_INVADED_BY_BEASTMEN                               = 12105,  -- Even if the city is invaded by beastmen, the Victory Gate alone must be defended to the last. It has been the pride of San d'Oria for generations! It must not fall!
        ACCESS_BEYOND_THE_VICTORY_GATE_IS_NOT_PERMITTED                       = 12106,  -- Access beyond the Victory Gate is not permitted at this time.
        THAT_RICH_BLACK_PLUMAGE_THOSE_STURDY_SURE_LEGS                        = 12107,  -- That rich, black plumage. Those sturdy, sure legs. Not like those scrawny green and blue chocobos you see the other nations turning out, huh?
        SAN_D_ORIAN_CHOCOBOS_ARE_OF_THE_FINEST                                = 12108,  -- San d'Orian chocobos are of the finest breeding. It goes without saying that our birds are far superior to those of Windurst and Bastok.
        BAKGODEK_VEGBREG_COME_SOON_YOU_DIE_ALL                                = 12109,  -- Bakgodek vegbreg... Come soon... You die all...
        MY_WORD_THOSE_FORSAKEN_ROYAL_KNIGHTS_IT_WAS                           = 12110,  -- My word, those forsaken Royal Knights... It was bad enough when I heard they were scavenging the broken weapons of the Orcs, but now they are leaving them strewn about the city!
        I_DON_T_KNOW_IF_THEY_INTEND_TO                                        = 12111,  -- I don't know if they intend to study them or use them as toys for our children! All I do know is that we Temple Knights will have to clean up their mess, as always!
        THIS_IS_THE_TERRITORY_OF_THE_YOUNG_GRIFFONS                           = 12112,  -- This is the territory of the Young Griffons. Leave if you have no business here! Those are the rules.
        HEEEY_THAT_S_NOT_FAIR_I_WANNA_GET                                     = 12113,  -- Heeey, that's not fair! I wanna get in, too!
        GREAT_POWER_LIES_IN_ONE_S_DRIVE_WHAT                                  = 12114,  -- Great power lies in one's drive. What drives you, adventurer?
        HERE_LET_ME_HAVE_A_TURN                                               = 12115,  -- Here, let me have a turn.
        HEY_DON_T_PUSH_MOVE_OVER                                              = 12116,  -- Hey, don't push! Move over!
        STOP_THAT_S_MINE                                                      = 12117,  -- Stop, that's mine!
        ID_12118                                                              = 12118,  -- ...
        I_M_GONNA_TELL                                                        = 12119,  -- I'm gonna tell!
        ACCORDING_TO_THE_LATEST_RUMORS_THE_BEASTMEN_ARE                       = 12120,  -- According to the latest rumors, the beastmen are after nothing more than crystals.
        IT_SEEMS_WE_ARE_NOT_THE_ONLY_INHABITANTS                              = 12121,  -- It seems we are not the only inhabitants of Vana'diel who are dependant on crystals for our survival.
        I_DON_T_THINK_ANY_HAD_IMAGINED_THAT                                   = 12122,  -- I don't think any had imagined that the scattered beastmen would conspire to align with one another. And then to organize an offensive, of all things! There must be a great and evil charisma at work...
        DO_YOU_KNOW_OF_THE_MULTINATIONAL_EXPEDITION_THAT                      = 12123,  -- Do you know of the Multinational Expedition that was dispatched to the cursed lands of the north ten years ago? I've heard that it was an extremely dangerous mission, and the team was met with many misfortunes.
        NOW_AS_LONG_AGO_IT_IS_THE_ORCS                                        = 12124,  -- Now, as long ago, it is the Orcs who are the archenemies of San d'Oria. I wonder how long we will remain at war with one another...
        WE_LOST_MANY_OF_OUR_FELLOW_KNIGHTS_IN                                 = 12125,  -- We lost many of our fellow knights in the battle at La Theine. To have suffered such a crushing defeat at the hands of the beastmen is...disconcerting.
        I_CANNOT_BELIEVE_WE_ALLOWED_THE_ORCS_TO                               = 12126,  -- I cannot believe we allowed the orcs to encircle our city... Still, though he commands the enemy, this Doggvdegg is a truly bold warrior.
        JUST_RECENTLY_I_SAW_A_MYSTERIOUS_CAT_LIKE                             = 12127,  -- Just recently I saw a mysterious cat-like figure donning a fire-red mantle pass right before my eyes on the battlefield. It moved with such speed and grace... Perhaps my eyes were playing tricks on me...
        THERE_ARE_RUMORS_THAT_THE_BEASTMAN_CONFEDERATE_NUMBERS                = 12128,  -- There are rumors that the Beastman Confederate numbers some 100,000 in total, but I find that hard to believe. The valor of the small Royal Knight contingent dispatched against the Orcish Hosts at Norvallen must not be overshadowed.
        THOSE_NORVALLEN_FEW_FOUGHT_UNFLINCHINGLY_TO_THE_VERY                  = 12129,  -- Those Norvallen few fought unflinchingly to the very brink of obliteration... Their leader, Marquis Leonoyne, was saved by the brave fighting of Count Alphonimile and his 300 noble troops.
        I_STILL_DON_T_UNDERSTAND_WHY_OUR_NATION                               = 12130,  -- I still don't understand why our nation must lower itself to allying with such a shady lot. I've heard that the Ru'Lude Summit had its fair share of complications. Not exactly all smiles and handshakes, if you know what I mean.
        THE_EXPANSION_OF_THE_ORCISH_HOSTS_IS_MUCH                             = 12131,  -- The expansion of the Orcish Hosts is much too fast as of late. Is San d'Oria not doing all that she can?
        COMMANDER_RONGELOUTS_S_KNIGHTS_OF_THE_IRON_RAM                        = 12132,  -- Commander Rongelouts's Knights of the Iron Ram are the most elite knights of the San d'Orian order. This red headgear is our trademark.
        A_FIERY_MASS_SOARED_FROM_THE_EASTERN_TO                               = 12133,  -- A fiery mass soared from the eastern to the western skies... To be honest, I felt that perhaps the end of time had come...
        THIS_IS_WATCHDOG_ALLEY_I_WOULD_NOT_TREAD                              = 12134,  -- This is Watchdog Alley. I would not tread too near the hanging cages down yonder path. Your presence may send the imprisoned fiends into a rage.
        GLORY_TO_THE_LION                                                     = 12135,  -- Glory to the lion!
        A_KNIGHT_S_WORK_IS_NEVER_DONE                                         = 12136,  -- A knight's work is never done...
        SWEEP_LIKE_YOU_MEAN_IT                                                = 12137,  -- Sweep like you mean it!
        IF_YOU_SEEK_ADMISSION_TO_THE_KNIGHTS_OF                               = 12138,  -- If you seek admission to the Knights of the Iron Ram, speak with Sir Mainchelite.
        LOOKING_TO_JOIN_THE_FIGHTING_FOURTH_SPEAK_TO                          = 12139,  -- Looking to join the Fighting Fourth? Speak to Centurion Adelbrecht. He'll assist you.
        SO_YOU_THINK_YOU_HAVE_WHAT_IT_TAKES                                   = 12140,  -- So you think you have what it takes to be a Cobra? Well, then talk to Miah Riyuh and hope that she's in a good mood!
        FOR_THE_LION                                                          = 12141,  -- For the lion!
        GIVE_EM_HELL                                                          = 12142,  -- Give 'em hell, %!
        SHOULDN_T_YOU_BE_OUT_CAMPAIGNING_NOW_GET                              = 12143,  -- Shouldn't you be out campaigning? Now get!
        I_SEE_YOU_SERVE_UNDER_ANOTHER_NATION                                  = 12144,  -- I see you serve under another nation.
        I_SEE_YOU_RE_WORKING_FOR_ANOTHER_NATION                               = 12145,  -- I see you're working for another nation.
        SAYS_HERE_YOU_VE_ALREADY_GONE_AND_JOINED                              = 12146,  -- Says here you've already gone and joined some other nation's forces.
        IF_YOU_SEEK_ADMISSION_TO_THE_KNIGHTS_OF_2                             = 12147,  -- If you seek admission to the Knights of the Iron Ram, speak with Sir Mainchelite.
        IF_YOU_RE_LOOKING_TO_JOIN_THE_FIGHTING                                = 12148,  -- If you're looking to join the Fighting Fourth, speak to Centurion Adelbrecht. He'll assist you.
        IF_YOU_VE_FINALLY_COME_TO_YOUR_SENSES                                 = 12149,  -- If you've finally come to your senses and decided on joining the Cobras then talk to Miah Riyuh...and hope that she's in a good mood!
        IF_YOU_SEEK_TO_REGAIN_ADMISSION_TO_THE                                = 12150,  -- If you seek to regain admission to the Knights of the Iron Ram, you must first sever ties with your nation of allegiance...and that will require Allied Notes.
        THOUGH_IF_YOU_WANT_TO_REJOIN_THE_FOURTH                               = 12151,  -- Though if you want to rejoin the fourth, I think something can be worked out. You have some Allied Notes, don't you?
        BUT_IF_YOU_VE_FINALLY_COME_TO_YOUR                                    = 12152,  -- But if you've finally come to your senses and decided to return to the Cobras, I think I can pull a few strings...for a price. You're carrying Allied Notes, right?
        PLEASE_NOTE_THAT_UPON_CHANGING_ALLEGIANCE_YOU_WILL                    = 12153,  -- Please note that upon changing allegiance, you will be required to return the two most prestigious campaign medals you possess. There is no penalty if you have yet to earn any medals.
        EXCHANGE_ALLIED_TO_TRANSFER_FROM_TO_YOU_CURRENTLY                     = 12155,  -- Exchange # Allied [Note/Notes] to transfer from [/the Knights of the Iron Ram/the Fourth Division/the Cobra Unit] to [/the Knights of the Iron Ram/the Fourth Division/the Cobra Unit]? You currently possess # [Allied Note/Allied Notes].
        PROCEED_WITH_THE_TRANSACTION_YES_NO_2                                 = 12156,  -- Proceed with the transaction? Yes. No.
        ARE_YOU_ABSOLUTELY_SURE_YES_NO                                        = 12157,  -- Are you absolutely sure? Yes. No.
        YOUR_TRANSFER_FROM_TO_IS_COMPLETE                                     = 12158,  -- Your transfer from [/the Knights of the Iron Ram/the Fourth Division/the Cobra Unit] to [/the Knights of the Iron Ram/the Fourth Division/the Cobra Unit] is complete.
        YOU_CANNOT_PLEDGE_YOUR_ALLEGIANCE_TO_ONE_NATION                       = 12159,  -- You cannot pledge your allegiance to one nation while undertaking initiation procedures of another. Withdraw your current application before attempting a transfer.
        YOU_RETURN_YOUR                                                       = 12160,  -- You return your %.
        YOU_ARE_NOW_A_MEMBER_OF_THE                                           = 12161,  -- You are now a member of the [/Knights of the Iron Ram/Republican Legion's Fourth Division/Cobra Unit]!
        YOU_DO_NOT_POSSESS_ENOUGH_ALLIED_NOTES_TO_2                           = 12162,  -- You do not possess enough Allied Notes to change your allegiance.
        I_M_TERRIBLY_SORRY_BUT_CHOCOBO_SERVICES_ARE                           = 12163,  -- I'm terribly sorry, but chocobo services are currently unavailable.
        BEYOND_THIS_GATEWAY_LIE_THE_IRON_RAM_BARRACKS                         = 12164,  -- Beyond this gateway lie the Iron Ram barracks. Here knights oil their blades before returning to the battlefield.
        IS_THAT_OVER_THERE                                                    = 12165,  -- Is that [her/him] over there?
        HM_WHY_I_DO_BELIEVE_IT_IS_HELLO                                       = 12166,  -- Hm? Why, I do believe it is! Hello there, ummm...new...pupil!
        I_DO_SAY_ULBRECHT_THE_LEAST_YOU_COULD                                 = 12167,  -- I do say, Ulbrecht, the least you could do is attempt to remember some of the new pupils' names.
        OH_HE_S_JUST_DOING_IT_ON_PURPOSE                                      = 12168,  -- Oh, he's just doing it on purpose. I believe he enjoys coming across a bit aloof. There's no point in chastising him. None ataru all.
        IT_S_NO_WONDER_ERLENE_IS_AT_HER                                       = 12169,  -- It's no wonder Erlene is at her wit's end.
        YOU_KNOW_FOR_PEERS_YOU_CERTAINLY_ARE_AN                               = 12170,  -- You know, for peers, you certainly are an unsparing lot.
        IF_HE_SHE_IS_MY_JUNIOR_THEN_IT                                        = 12171,  -- If he/she] is my junior, then it stands to reason that he/she] is junior to all of you as well. Might I be so bold as to ask exactly how you all came to hold yourselves above the standards you so eagerly apply to others?
        YOU_CERTAINLY_ARRIVED_SOONER_THAN_I_EXPECTED                          = 12172,  -- You certainly arrived sooner than I expected, %.
        IF_EVEN_THE_NEW_PUPIL_HAS_ARRIVED_BY                                  = 12173,  -- If even the new pupil has arrived by now, what do you gather is keeping Fhen?
        EVEN_CONSIDERING_THE_DISTANCE_FROM_WINDURST_THERE_IS                  = 12174,  -- Even considering the distance from Windurst, there is no reason she should be so delayed.
        WE_FIRST_SCHEDULED_THIS_MEETING_SOME_TIME_AGO                         = 12175,  -- We first scheduled this meeting some time ago. There are, however, some parties who have yet to arrive.
        UNFORTUNATELY_THERE_ARE_URGENT_MATTERS_ELSEWHERE_WHICH_DEMAND         = 12176,  -- Unfortunately, there are urgent matters elsewhere which demand our immediate attention. I'm afraid I can only offer you the briefest of explanations.
        INITIAL_INVESTIGATIONS_CONDUCTED_BY_SECURITY_FORCES_ON_BEHALF         = 12177,  -- Initial investigations conducted by security forces on behalf of all nations have yielded disconcerting results. The Beastmen may well be seeking to compromise the Allied Forces' decision-making and strategizing capabilities through a series of sneak attacks on our magic-wielding intelligentsia.
        A_DIVERSIONARY_TACTIC_TO_BE_SURE_THEY_WILL                            = 12178,  -- A diversionary tactic, to be sure. They will most likely change their play while we are occupied with gathering intel.
        I_SEE_PLANS_WITHIN_PLANS                                              = 12179,  -- I see plans within plans...
        THAT_IS_WHERE_WE_SCHOLARS_COME_IN                                     = 12180,  -- That is where we scholars come in.
        SUFFICE_IT_TO_SAY_THAT_WE_HAVE_CERTAIN                                = 12181,  -- Suffice it to say that we have certain...means...of taking care of this type of thing. Each nation has its own specialistarus who revel in flushing out fugi-wugitives at large.
        THAT_IS_IN_PART_WHY_WE_SOUGHT_TO                                      = 12182,  -- That is in part why we sought to convene here today. It was our belief that a thorough analysis of the information we have all gathered would naturally reveal the identity of the culprit.
        YET_WE_ARE_MISSING_A_KEY_PIECE_I                                      = 12183,  -- Yet we are missing a key piece. I fear... No, it would be improper of me to say.
        SURELY_YOU_AREN_T_IMPLYING_THAT_SOMETHING_HAS                         = 12184,  -- Surely you aren't implying that something has happened to Fhen!?
        YOU_ARE_TOO_QUICK_TO_JUMP_TO_CONCLUSIONS                              = 12185,  -- You are too quick to jump to conclusions. The war rages to new expanses with each passing day. It is by no means an understatement to say that the safe roads of passage have all but disappeared from both continents.
        NOT_TO_MENTION_THAT_FHEN_IS_THE_PROFESSOR                             = 12186,  -- Not to mention that Fhen is the professor's most stellar pupil. It is no small feat to have mastered the Schultzian arts to the extent that she has. I would gladly put my gil on her, should any beastman be foolish enough to cross her path.
        TRUE_ENOUGH                                                           = 12187,  -- True enough.
        SO_WHAT_DO_YOU_PROPOSE_WE_DO                                          = 12188,  -- So what do you propose we do?
        THIS_COUNCIL_WILL_DISBAND_FOR_THE_TIME_BEING                          = 12189,  -- This council will disband for the time being. And the main roads between Windurst and here should be scoured with a fine-toothed comb.
        I_SEE_NO_OTHER_ALTERNATIVES                                           = 12190,  -- I see no other alternatives.
        THEN_THAT_SETTLES_IT                                                  = 12191,  -- Then that settles it.
        THOUGH_YOUR_JOURNEY_HAS_JUST_ENDED_I_ASK                              = 12192,  -- %, though your journey has just ended, I ask that you head back to inform Erlene of what has transpired here.
        AFTER_THAT_PLEASE_AID_IN_THE_SEARCH_FOR                               = 12193,  -- After that, please aid in the search for Fhen. We shall meet again in Sauromugue Champaign. Go now.
        ALL_CLEAR_TO_THE_NORTH_ALL_CLEAR_TO                                   = 12194,  -- All clear to the north! All clear to the east! No enemies detected! Perimeter secured!
        AH_HECTIC_IS_THE_LIFE_OF_A_CASTELLAN                                  = 12195,  -- Ah, hectic is the life of a castellan. But ever vigilant must I remain in the absence of Captain Rahal and the others.
        GREETINGS_EXCEPTIONAL_TIMING_AS_ALWAYS_IN_MY_AUTHORITY                = 12196,  -- Greetings, %! Exceptional timing, as always! In my authority as Castellan of Swiftwing Fortress, I relay to you these mission orders.
        YOU_ARE_TO_GATHER_AND_BRING_HITHER_THE                                = 12197,  -- You are to gather and bring hither the following three items:
        FIRST                                                                 = 12198,  -- First, %.
        MAKING_CUTS_ON_TREE_TRUNKS_OUT_IN_RONFAURE                            = 12199,  -- Making cuts on tree trunks out in Ronfaure should yield an adequate amount.
        NEXT_ON_THE_LIST_SOME                                                 = 12200,  -- Next on the list, some %.
        THESE_ARE_OFT_STOWED_WITHIN_THE_CAVITY_OF                             = 12201,  -- These are oft stowed within the cavity of trees throughout the Kingdom in preparation for times of emergency. Rest assured, we shall only be borrowing them.
        WHICH_BRINGS_US_TO_THE_THIRD_AND_FINAL                                = 12202,  -- Which brings us to the third and final item, %.
        FOR_THIS_YOU_NEED_BUT_DRAW_WATER_FROM                                 = 12203,  -- For this, you need but draw water from the well over yonder.
        THAT_CONCLUDES_YOUR_ORDERS                                            = 12204,  -- That concludes your orders!
        THE_FIRST_ITEM_ON_THE_LIST_IS                                         = 12205,  -- The first item on the list is %.
        MAKING_CUTS_ON_TREE_TRUNKS_OUT_IN_RONFAURE_2                          = 12206,  -- Making cuts on tree trunks out in Ronfaure should yield an adequate amount.
        NEXT_ON_THE_LIST                                                      = 12207,  -- Next on the list, %.
        THESE_ARE_OFT_STOWED_WITHIN_THE_CAVITY_OF_2                           = 12208,  -- These are oft stowed within the cavity of trees throughout the Kingdom.
        IS_THE_THIRD_AND_FINAL_ITEM                                           = 12209,  -- % is the third and final item.
        FOR_THIS_YOU_NEED_BUT_DRAW_WATER_FROM_2                               = 12210,  -- For this, you need but draw water from the well over yonder.
        THAT_CONCLUDES_THE_LIST_OF_ITEMS_REPORT_BACK                          = 12211,  -- That concludes the list of items. Report back to me upon procurement and you will be further briefed.
        A_CONTAINER_OF_UTILITARIAN_DESIGN_HAS_BEEN_STOWED                     = 12212,  -- A container of utilitarian design has been stowed inside the tree hollow.
        YOU_DRAW_WATER_FROM_THE_WELL                                          = 12213,  -- You draw water from the well.
        WHAT_YOU_WOULD_KNOW_MY_OPINION_OF_THE                                 = 12214,  -- What? You would know my opinion of the Swiftwing Griffins?
        THE_HAVE_UNEXPECTEDLY_RIGID_BACKBONES_FOR_A_BUNCH                     = 12215,  -- The have unexpectedly rigid backbones...for a bunch of maggots. But many more indignities must be overcome on their part if they hope to become anything more than ankle weights.
        NOW_THEN_HOW_DO_YOU_EXPLAIN_YOUR_DAWDLING                             = 12216,  -- Now then. How do you explain your dawdling here? For every minute you stand in idle inactivity, the Kingdom loses ground to the enemy.
        IF_YOU_SEEK_CAPTAIN_RAHAL_I_FEAR_HE                                   = 12217,  -- If you seek Captain Rahal, I fear he has yet to return.
        I_HAVE_A_UNIT_OF_KNIGHTS_TO_OVERSEE                                   = 12218,  -- I have a unit of knights to oversee. If you've nothing of import to discuss, then away with you.
        WELCOME_BACK_LET_S_SEE_WHAT_YOU_VE                                    = 12219,  -- Welcome back, %. Let's see what you've brought... Maple syrup, long-life biscuits, and freshly drawn water. All appears to be in good order!
        VOILA_I_GIVE_YOU_BISCUITS_A_LA_RHOLONT                                = 12220,  -- Voila! I give you biscuits a la Rholont!
        HM_WHY_DID_I_PREPARE_SUCH_A_DELECTABLE                                = 12221,  -- Hm? Why did I prepare such a delectable treat, you ask?
        CAPTAIN_RAHAL_AND_A_FEW_OTHERS_FROM_OUR                               = 12222,  -- Captain Rahal and a few others from our unit, you see, have convened out in Jugner Forest to participate in a strategy meeting with the Iron Rams.
        MY_SOURCES_TELL_ME_THAT_THE_SWIFTWING_GRIFFINS                        = 12223,  -- My sources tell me that the Swiftwing Griffins will be awarded the charge of escorting the Royal Provisioners--a responsibility of considerable import in anyone's book.
        THE_BISCUITS_WILL_BE_PIVOTAL_IN_HELPING_OUR                           = 12224,  -- The biscuits will be pivotal in helping our men fend off untimely hunger pangs during the proceedings. Without sustenance, they couldn't hope to survive one of Captain Rongelouts's legendarily verbose sermons.
        I_WOULD_MAKE_THE_DELIVERY_MYSELF_BUT_FOR                              = 12225,  -- I would make the delivery myself, but for my post as Castellan of Swiftwing Fortress. Therefore, in my stead, I bid you take the biscuits to our people in Jugner Forest.
        MAY_THE_GODDESS_SPEED_YOUR_WAY                                        = 12226,  -- May the Goddess speed your way, %!
        THE_SWIFTWING_GRIFFINS_ARE_CURRENTLY_ON_STANDBY_OUT                   = 12227,  -- The Swiftwing Griffins are currently on standby out in Jugner Forest for a strategy meeting with the Iron Rams.
        PLEASE_SEE_TO_IT_THAT_THE_ARE_SAFELY                                  = 12228,  -- Please see to it that the % are safely delivered to the hands of Captain Rahal.
        WELCOME_BACK_FROM_YOUR_MISSION_DID_OUR_MEN                            = 12229,  -- Welcome back from your mission! Did our men take heart from the special rations we prepared?
        YOU_SEEK_MACHEGUE_HE_DEPARTED_THE_FORTRESS_NOT                        = 12230,  -- You seek Machegue? He departed the fortress not a moment after returning from afield. In his haste, he scarce had the breath to inform me that he was headed for Vunkerl Inlet.
        AH_WELCOME_BACK                                                       = 12231,  -- Ah! Welcome back, %!
        RELIEVED_AM_I_TO_SEE_YOU_SAFE_AND                                     = 12232,  -- Relieved am I to see you safe and sound. To a castellan, few things are more gratifying than receiving one's own back from afield.
        GREETINGS_FROM_WHAT_CAPTAIN_RAHAL_HAS_TOLD_ME                         = 12233,  -- Greetings, %. From what Captain Rahal has told me of recent happenings, you've been on quite a ride.
        THE_MOST_IMPORTANT_THING_IS_THAT_YOU_VE                               = 12234,  -- The most important thing is that you've not come to any harm.
        AT_THIS_VERY_MOMENT_THE_CAPTAIN_SHOULD_BE                             = 12235,  -- At this very moment, the captain should be making a report to Royal Knight General Cousseraux himself. Our unit continues its meteoric rise to distinction!
        ID_12236                                                              = 12236,  -- %!
        TIS_GOOD_TO_SEE_YOU_BACK                                              = 12237,  -- 'Tis good to see you back.
        BUT_YOUR_BEING_HERE_WOULD_MEAN_THAT_ORCISH                            = 12238,  -- But...your being here would mean that Orcish intelligence on the Cardinal Stags' location was inaccurate?
        THAT_REMINDS_ME_WERE_CYRANUCE_AND_MACHEGUE_NOT                        = 12239,  -- That reminds me, were Cyranuce and Machegue not with you, %?
        WH_WHAT                                                               = 12240,  -- Wh-what?
        MACHEGUE_IS                                                           = 12241,  -- Machegue...is...?
        ID_12242                                                              = 12242,  -- ...
        TELL_US_THIS_ISN_T_SO_THAT_THIS                                       = 12243,  -- Tell us this isn't so, %... That this is but a tasteless jest...
        I_CANNOT_BELIEVE_IT                                                   = 12244,  -- I cannot believe it...
        ID_12245                                                              = 12245,  -- %.
        TAKE_ME_TO_THE_PASHHOW_MARSHLANDS_TO_WHERE                            = 12246,  -- Take me to the Pashhow Marshlands, to where Machegue is. As Captain, I need--I need to...
        GOING_SOMEWHERE_MAGGOT                                                = 12247,  -- Going somewhere, maggot?
        ID_12248                                                              = 12248,  -- !!!
        C_CAPTAIN_RONGELOUTS_I_VE_NOT_TIME_TO                                 = 12249,  -- C-Captain Rongelouts... I've not time to linger. Please let me pass.
        SO_YOU_HAVE_THE_BLOOD_OF_ONE_OF                                       = 12250,  -- So...you have the blood of one of your own on your hands.
        WHAT                                                                  = 12251,  -- What!?
        SEIZE_HIM                                                             = 12252,  -- Seize him.
        WH_WHAT_IS_THE_MEANING_OF_THIS_UNHAND                                 = 12253,  -- Wh-what is the meaning of this? Unhand me! Unhand me, I say!
        TAKE_HIM_AWAY                                                         = 12254,  -- Take him away.
        C_CAPTAIN_RAHAL                                                       = 12255,  -- C-Captain Rahal!
        I_OWE_YOU_FOR_THAT_TIME_BACK_AT                                       = 12256,  -- I owe you for that time back at the Garlaige Citadel.
        THE_KNIGHTS_OF_THE_CARDINAL_STAG_HAVE_ALTERED                         = 12257,  -- The Knights of the Cardinal Stag have altered their course and now pass through the Pashhow Marshlands, correct?
        INDEBTED_AS_I_ALREADY_AM_I_MUST_ASK                                   = 12258,  -- Indebted as I already am, I must ask for yet another favor. I need you to take this letter and see it to the hands of Alphonimile.
        WE_GO_A_LONG_WAY_BACK_HE_AND                                          = 12259,  -- We go a long way back, he and I. It is imperative that the words sealed within are made known to him.
        I_M_COUNTING_ON_YOU                                                   = 12260,  -- I'm counting on you.
        I_HOPE_THE_CAPTAIN_IS_ALL_RIGHT                                       = 12261,  -- I hope the captain is all right...
        MACHEGUE                                                              = 12262,  -- Machegue...
        THAT_WE_WILL_NEVER_SEE_MACHEGUE_AGAIN_THE                             = 12263,  -- That we will never see Machegue again... The reality of it has yet to sink in.
        BEST_YOU_DELIVER_THE_LETTER_TO_ALPHONIMILE_WHILE                      = 12264,  -- Best you deliver the letter to Alphonimile while the Cardinal Stags have yet to depart the Pashhow Marshlands. I'm counting on you.
        SO_HE_RESUMED_THE_EXPEDITION_TO_TAVNAZIA_EVEN                         = 12265,  -- So, he resumed the expedition to Tavnazia, even after the behemoth was defeated...
        NOT_THAT_I_HAD_EXPECTED_ALPHONIMILE_TO_DO                             = 12266,  -- Not that I had expected Alphonimile to do otherwise. He's been a man of unwavering resolve for as long as I've known him.
        THAT_REMINDS_ME_IT_S_TIME_TO_RELEASE                                  = 12267,  -- That reminds me, it's time to release that lively little maggot from his confinement in the barracks.
        THANKS_TO_YOU_ONE_MORE_MAGGOT_HAS_A                                   = 12268,  -- Thanks to you, one more maggot has a fighting chance of maturing into a fly.
        TAKE_THIS_AS_A_SMALL_EXPRESSION_OF_MY                                 = 12269,  -- Take this as a small expression of my gratitude. You've earned it.
        COMPANY_HALT                                                          = 12270,  -- Company, halt!
        AN_UNSEASONAL_STORM_EVEN_NATURE_FANCIES_TO_DECLARE                    = 12271,  -- An unseasonal storm? Even nature fancies to declare war on us...
        DO_MY_EYES_PLAY_TRICKS_THE_SKY_IS                                     = 12272,  -- Do my eyes play tricks? The sky...is shaking?
        TH_THAT_LIGHT                                                         = 12273,  -- Th-that light!?
        HMM                                                                   = 12274,  -- Hmm!?
        CARDINAL_STAGS_SEEK_SHELTER                                           = 12275,  -- Cardinal Stags, seek shelter!
        HMM_THIS_IS_HAPPENING_A_LITTLE_EARLIER_THAN                           = 12276,  -- (Hmm... This is happening a little earlier than was recorded in history...)
        EARTHQUAKE                                                            = 12277,  -- (Earthquake!?)
        THAT_STRANGE_LIGHT_ZOGBOG_YOU_SPEAK_OF_EXPLOSION                      = 12278,  -- (That strange light!? Zogbog, you speak of explosion...)
        TWAS_INDEED_THE_EXPLOSION_OF_WHICH_I_SPOKE                            = 12279,  -- ('Twas indeed the explosion of which I spoke, my lord.)
        YOU_HAVE_JUST_WITNESSED_THE_SEPARATION_OF_THE                         = 12280,  -- (You have just witnessed the separation of the Tavnazian Peninsula from the mainland, and the ensuing birth of the Tavnazian Archipelago.)
        I_CAN_T_BELIEVE_MORE_THAN_SIXTY_THOUSAND                              = 12281,  -- (I can't believe... More than sixty thousand of our soldier there...)
        TIS_UNFORTUNATE_MY_LORD_BUT_A_GREAT_MANY                              = 12282,  -- ('Tis unfortunate, my lord, but a great many of them shall never again set foot on the face of Vana'diel.)
        ID_12283                                                              = 12283,  -- ...
        BUT_TAKE_HEART_FOR_FAILURE_IS_THE_MOTHER                              = 12284,  -- (But take heart, for failure is the mother of success.)
        WHAT_YOU_SAY                                                          = 12285,  -- (What you say?)
        TIS_ONLY_A_MATTER_OF_TIME_BEFORE_THE                                  = 12286,  -- ('Tis only a matter of time before the walls of Tavnazia crumble beneath the weight of our remaining three behemoths.)
        FURTHERMORE                                                           = 12287,  -- (Furthermore...)
        MEMBERS_OF_THE_BLOODWING_HORDE_THAT_WERE_RELIEVED                     = 12288,  -- (Members of the Bloodwing Horde that were relieved by the beasts--a goodly two thousand elite soldiers--have been returned to your service unscathed.)
        WITH_THEM_UNDER_YOUR_LEADERSHIP_YOUR_AUTHORITY_OVER                   = 12289,  -- (With them under your leadership, your authority over the ever-weakening armies of the Shadow Lord is certain to flourish.)
        HMM_YOU_SPEAK_TRUTH                                                   = 12290,  -- (Hmm... You speak truth.)
        I_KEEP_PROMISE_I_GRANT_YOU_COMMAND_OF                                 = 12291,  -- (I keep promise. I grant you command of five hundred elite.)
        M_MY_LORD_YOUR_GENEROSITY_IS_BOUNDLESS                                = 12292,  -- (M-my lord! Your generosity is boundless!)
        NOW_THEN_WHAT_DO_YOU_GET_WHEN_TWO                                     = 12293,  -- (Now then... What do you get when two thousand battle-hardened soldiers of the Bloodwing Horde purportedly lost in Tavnazia find themselves in Xarcabard?)
        THE_PLOT_THICKENS                                                     = 12294,  -- (The plot thickens...)
        GAHAHAHAHA                                                            = 12295,  -- (Gahahahaha...)
        THE_ENTIRE_KINGDOM_IS_IN_AN_UPROAR_WITH                               = 12296,  -- The entire Kingdom is in an uproar with talk of the secret weapon supposedly employed by the beastmen at Tavnazia.
        WHY_SOME_OF_THE_RUMORS_EVEN_GO_SO                                     = 12297,  -- Why, some of the rumors even go so far as to suggest that the entire Tavnazian Peninsula was wiped off the map! Could such a horrendous thing truly have taken place?
        BUT_AS_THE_SAYING_GOES_WHERE_THERE_IS                                 = 12298,  -- But as the saying goes, where there is smoke, there is fire... We can only hope that no harm has befallen Excenmille.
        ALL_COMMUNICATION_WITH_THE_MARQUISATE_HAS_CEASED_SINCE                = 12299,  -- All communication with the Marquisate has ceased since that unexplained occurrence...
        CONFOUND_IT_HAD_ONLY_WE_CONCLUSIVE_EVIDENCE_I                         = 12300,  -- Confound it! Had only we conclusive evidence, I would have stopped at nothing to prevent him from continuing on to Tavnazia!
        AH_SQUIRE_ALTENNIA_APPROACHES                                         = 12301,  -- Ah, Squire Altennia! % approaches!
        WELL_MET_IT_DOES_MY_SPIRIT_WELL_TO                                    = 12302,  -- Well met, %. It does my spirit well to see you again.
        YOU_COME_AT_A_GOOD_TIME_SQUIRE_ALTENNIA                               = 12303,  -- You come at a good time. Squire Altennia is presently briefing me on the latest developments on the war front.
        THE_MAIN_HOST_OF_THE_ALLIED_FORCES_NORTHERN                           = 12304,  -- The main host of the Allied Forces' northern expedition now marches for Xarcabard.
        MY_UNIT_THE_CARMINE_SWALLOWS_HAS_BEEN_RECALLED                        = 12305,  -- My unit, the Carmine Swallows, has been recalled from furlough and will shortly depart to merge with them.
        AND_THAT_IS_WHY_I_COME_HERE_TODAY                                     = 12306,  -- And that is why I come here today...to say my farewells. In this age of tumult, we know not when a meeting with loved ones may prove to be the last.
        ALL_WILL_BE_WELL_SURELY_FROM_THE_BITS                                 = 12307,  -- All will be well, surely. From the bits and pieces of rumor I've scavenged from Kingdom knights, the beastman force is in decline, and far from the menacing presence it once was.
        THE_GRIFFIN_S_NOSE_FOR_INTELLIGENCE_IS_AS                             = 12308,  -- The Griffin's nose for intelligence is as keen as ever, I see. But a mystery lies amidst this trend of decline, to be sure. Many an eyebrow has been raised over why a great many Orcs survived Tavnazia and now prowl the Northlands in force when other beastman units were nigh annihilated.
        TAVNAZIA_ANNIHILATED                                                  = 12309,  -- Tavnazia...? Annihilated...?
        OH_UM_NEVER_MIND_THAT_TIS_NOTHING_OF                                  = 12310,  -- Oh, um...never mind that. 'Tis nothing of significance.
