        YEAH_ABOUT_TIME_WE_WERE_HEADING_OUT_WE                                = 12664,  -- Yeah, about time we were heading out. We'll see you there, %!
        GREAT_ALTANA_GRANT_YOUR_MERCY_TO_ALL_YOUR                             = 12665,  -- Great Altana, grant your mercy to all your children...
        THERE_IS_NO_RESPONSE_TO_YOUR_KNOCKING                                 = 12666,  -- There is no response to your knocking.
        HO_THERE_FROM_FAIR_WINDURST_ARE_YOU_NOT                               = 12667,  -- Ho there! % from fair Windurst, are you not? Well met!
        NO_DOUBT_YOUR_LEGS_ARE_WEARY_FROM_THE                                 = 12668,  -- No doubt your legs are weary from the road, but I have orders to escort you to the castle at once. All parties have assembled, and there is much that needs be discussed.
        AS_HAS_BEEN_CONFIRMED_BY_THE_KINGDOM_S                                = 12669,  -- ...As has been confirmed by the Kingdom's elite scouts...
        AH_I_WAS_WONDERING_WHEN_YOU_D_SHOW                                    = 12670,  -- (Ah, %, I was wondering when you'd show up! Quickly, over here...the meeting's already begun!)
        AND_WHO_MIGHT_THIS_GENTLEMAN_LADY_BE                                  = 12671,  -- And who might this gentleman/lady] be?
        A_MERCENARY_UNDER_OUR_COMMAND_PARDON_THE_INTERRUPTION                 = 12672,  -- A mercenary under our command. Pardon the interruption. Please continue.
        AN_ALLY_OF_WINDURST_PARDON_THE_INTERRUPTION_PLEASE                    = 12673,  -- An ally of Windurst. Pardon the interruption. Please continue.
        THE_STATELY_LOOKING_FELLOW_DOING_ALL_THE_TALKING                      = 12674,  -- (The stately looking fellow doing all the talking is Valaineral R Davilles, Captain of the San d'Orrrian Royal Guards. He's brrriefing all officers on the tactical situation as it currently stands.)
        HOSTS_FROM_EACH_OF_THE_THREE_BEASTMAN_NATIONS                         = 12675,  -- Hosts from each of the three beastman nations--Orc, Quadav, and Yagudo--are mobilizing in the north even as we speak. We have every reason to believe that they do so at the behest of the Shadow Lord himself.
        THE_CONFEDERATE_HAS_DIVIDED_THEIR_FORCES_BETWEEN_THE                  = 12676,  -- The Confederate has divided their forces between the Tavnazian and Valdeaunian fronts. Both are amassing resources and manpower, girding themselves for a full-scale offensive on our lands.
        ANY_FURTHER_DELAY_WILL_MEAN_OUR_CERTAIN_DESTRUCTION                   = 12677,  -- Any further delay will mean our certain destruction.
        THUSLY_WE_MOVE_AT_ONCE_WE_MARCH_ON                                    = 12678,  -- Thusly, we move at once. We march on Valdeaunia and commence the siege of Castle Zvahl forthwith.
        OUR_FIRST_OBJECTIVE_WILL_BE_TO_ESTABLISH_POSITION                     = 12679,  -- Our first objective will be to establish position in Xarcabard and the Beaucedine Glacier. From there, we will surround Castle Zvahl and strike at the heart of our foe.
        COMMANDERS_READY_YOUR_TROOPS_FOR_THE_BATTLE_OF                        = 12680,  -- Commanders, ready your troops for the battle of their lives. We leave for Valdeaunia on the morrow.
        A_DETAILED_BRIEFING_WILL_BE_HELD_UPON_OUR                             = 12681,  -- A detailed briefing will be held upon our arrival.
        IN_CLOSING_A_WORD_TO_ALL_OF_YOU                                       = 12682,  -- In closing, a word to all of you.
        I_STAND_HERE_AND_SEE_BEFORE_ME_WINDURSTIANS                           = 12683,  -- I stand here, and see before me Windurstians, Bastokers, and San d'Orians. I see men and women who, in days past, might once have crossed swords as enemies.
        TO_SEE_YOU_TODAY_UNITED_UNDER_ONE_BANNER                              = 12684,  -- To see you today, united under one banner for the glory of the Goddess, fills me with pride such as I have never known.
        THE_BATTLE_WILL_BE_ARDUOUS_THE_ENEMY_UNYIELDING                       = 12685,  -- The battle will be arduous, the enemy unyielding. But with your courage and valor, Altana's children will live to see a brighter day. Dismissed!
        WARLOCK_WARLORD_SIR                                                   = 12686,  -- Warlock Warlord, sir!
        AN_URGENTARU_TRANSMISSION_HAS_JUST_COME_IN_FROM                       = 12687,  -- An urgentaru transmission has just come in from the Leonian War Warlocks! P-p-please, takey-wake a listen!
        MASTER_CASTER_DORON_FULUN_OF_THE_LEONIAN_WAR                          = 12688,  -- Master Caster Doron-Fulun of the Leonian War Warlocks reportaruing, Warlock Warlord sir! I have grave news!
        THIS_IS_ROBEL_AKBEL_SPEAK                                             = 12689,  -- This is Robel-Akbel. Speak.
        OUR_SCOUTS_JUSTARU_RETURNED_FROM_CASTLE_ZVAHL_AND                     = 12690,  -- Our scouts justaru returned from Castle Zvahl, and-- Wh-wh-what the--? What are you doing!? L-l-let go of me!!! Noooooooooooo!!!
        HAVE_WE_LOSTARU_HIM                                                   = 12692,  -- ... Have we...lostaru him?
        ID_12693                                                              = 12693,  -- <...>
        O_HOHOHOHOHO                                                          = 12694,  -- O`hohohohoho!
        BE_QUIET_FOR_A_SPELL_AND_LISTEN_GOOD                                  = 12695,  -- Be quiet for a spell, and listen good and well.
        THAT_VOICE                                                            = 12696,  -- (That voice...!?)
        AS_YOU_MARCH_UNWITTINGLY_TOWARD_THE_SHADOW_LORD                       = 12697,  -- As you march unwittingly toward the Shadow Lord's front door, the enemy has stealthily prepared another, secret corps.
        WHAT_S_MORE_THIS_SECOND_ARMY_HAS_BEEN                                 = 12698,  -- What's more, this second army has been set in motion. A direct assault on Windurst, would appear to be their notion.
        TEN_THOUSAND_OR_MORE_BY_MY_ROUGH_COUNT                                = 12699,  -- Ten thousand or more, by my rough count. No matter how you slice it, a formidable amount.
        WHAT_3                                                                = 12700,  -- What!?
        I_MIGHT_HAVE_HANDLED_THEM_ON_MY_OWN                                   = 12701,  -- I might have handled them on my own, if I weren't stuck with your hapless War Warlocks to chaperone.
        ROBEL_AKBEL_AMEND_YOUR_PLANS_ON_THE_DOUBLE                            = 12702,  -- Robel-Akbel. Amend your plans on the double, or watch as the Federation is reduced to so much rubble!
        YOUR_REPORT_IS_APPRECIATED_PROFESSOR_THAT_WAS_EXACTLY                 = 12703,  -- Your report is appreciated, Professor. That was exactly the information I needed to plot the necessary countermeasures.
        THE_ALLIED_FORCES_WILL_PROCEED_FOR_VALDEAUNIA_AS                      = 12704,  -- The Allied Forces will proceed for Valdeaunia as scheduled. You and the Leonians are to join us there.
        YES_I_SUPPOSE_I_CAN_DO_AS_YOU                                         = 12705,  -- Yes, I suppose I can do as you say. Though I'll trust you not to get in my way! O`hohohohoho!
        AND_SO_IT_BEGINS                                                      = 12706,  -- And so it begins...
        LEHKO_SEND_WORD_TO_THE_FEDERATION_AT_ONCE                             = 12707,  -- Lehko! Send word to the Federation at once.
        THEIR_NUMBERS_EXCEED_OUR_ESTIMATES_YOU_ARE_TO                         = 12708,  -- Their numbers exceed our estimates. You are to take command of the Cobras and stave the enemy off at Karugo-Narugo.
        UNDERSTOOD_3                                                          = 12709,  -- Understood.
        MY_ESTEEMED_ROBEL_AKBEL_WHATEVER_IS_THE_COMMOTION                     = 12710,  -- My esteemed Robel-Akbel, whatever is the commotion?
        EXCUSE_MY_DISCOURTESY_LORD_VALAINERAL_IT_APPEARS_THAT                 = 12711,  -- Excuse my discourtesy, Lord Valaineral. It appears that the Federation will have some unexpected guests. I've ordered Lehko and the Cobra Mercenaries back to the fort.
        GUESTS_YOU_SAY                                                        = 12712,  -- Guests, you say?
        I_SEE_ONCE_YOU_VE_REGALED_THEM_PROPERLY                               = 12713,  -- ...I see. Once you've regaled them properly, make haste to join us in the north. The battle will not be won without your aid.
        YES_MILORD                                                            = 12714,  -- Yes, milord.
        WELL_ROMAA_YOU_HEARD_THE_WARLOCK_WARLORD_WE                           = 12715,  -- Well, Romaa, %...you heard the Warlock Warlord. We'd best head back to make preparrrations for the banquet.
        BUT_BEFORE_THAT_WELL_IT_WOULD_BE_THE                                  = 12716,  -- But before that... Well, it would be the height of rrrudeness to show up at the party empty-handed, don't you think?
        WHAT_SAY_WE_BRING_BACK_A_PRRRESENT_TO                                 = 12717,  -- What say we bring back a prrresent to liven up the festivities a tad?
        A_PRESENT_YOU_SAY                                                     = 12718,  -- A present, you say...?
        HEHEHE_DON_T_WORRY_I_HAVE_JUST_THE                                    = 12719,  -- Hehehe... Don't worry, I have just the thing in mind. A few hours ago, on the way to the briefing, I came across an Allied supply carrravan transporting a stockpile of arms.
        A_QUICK_PEEK_INSIDE_THE_WAGON_TURNED_UP                               = 12720,  -- A quick peek inside the wagon turned up some items of particular interrrest: % and %...
        I_FIGURRRE_THEY_WOULDN_T_MISS_A_FEW                                   = 12721,  -- I figurrre they wouldn't miss a few of them...what do you think?
        YOU_RE_NOT_SUGGESTING_THAT_WE_STEAL_FROM                              = 12722,  -- You're not suggesting that we steal from the Allied arrrsenal!?
        STEAL_HARDLY_AS_FULL_FLEDGED_MEMBERS_OF_THE                           = 12723,  -- Steal...? Hardly! As full-fledged members of the Allied Forces, we have as much right to these supplies as anyone! Why leave them to collect dust in an armory somewhere when we could put them to so much better use, no?
        I_M_NOT_SO_SURRRE_ABOUT_THIS_ONE                                      = 12724,  -- I'm not so surrre about this one...
        COME_ON_HAVE_I_EVER_LED_YOU_ASTRRRAY                                  = 12725,  -- Come on, have I ever led you astrrray? Trust me...I have a plan.
        REMEMBER_OUR_RECENT_SKIRMISH_IT_WAS_THAT_MAGIC                        = 12726,  -- Remember our recent skirmish? It was that magic-resistant armor the beastmen were wearing that proved so trrroublesome.
        IF_WE_COULD_SOMEHOW_USE_THE_AND_TO                                    = 12727,  -- If we could somehow use the % and % to produce ammunition that could pierce through their protection...
        WE_COULD_BLAST_THEIR_MAGIC_ARMOR_RIGHT_OFF                            = 12728,  -- We could blast their magic armor right off, and rrrender them all but defenseless before they even know what's hit them!
        EVER_THE_RRRESOURCEFUL_ONE_AREN_T_YOU_LEHKO                           = 12729,  -- Ever the rrresourceful one, aren't you, Lehko? Fine. You can take responsibility when Valaineral comes for our heads!
        HAHAHA_WHEN_OUR_PLAN_WINS_US_A_RRROUSING                              = 12730,  -- Hahaha...when our plan wins us a rrrousing victory at Karugo-Narugo, he's more likely to award us medals of honor!
        ALL_RIGHT_FIRST_TO_CONVINCE_THAT_STERN_LOOKING                        = 12731,  -- All right! First, to convince that stern-looking gentleman over there of the rrrighteousness of our cause...
        ALL_RIGHT_I_M_COUNTING_ON_YOU_A                                       = 12732,  -- (All right, I'm counting on you, %! A few arrrtful words, and the % and % will be ours!)
        A_MOMENT_OF_YOUR_TIME_GOOD_SIR                                        = 12733,  -- A moment of your time, good sir!
        YES_I_M_A_BUSY_MAN_STATE_YOUR                                         = 12734,  -- Yes? I'm a busy man. State your business, then begone with you.
        OH_T_WILL_ONLY_BE_A_SECOND_I                                          = 12735,  -- Oh, t'will only be a second. I couldn't help but notice the % and % you were carrying just before...
        YES_WHAT_OF_THEM_THEY_ARE_RESERVE_ARMAMENTS                           = 12736,  -- Yes? What of them? They are reserve armaments that we were transporting to our secret cache. Can't very well leave such dangerous materials lying about the street, after all.
        OH_BUT_CERTAINLY_I_CAN_SEE_THAT_YOU                                   = 12737,  -- Oh, but certainly! I can see that you are most prrrudent in your duties! But this cache you speak of...might I inquire as to its whereabouts?
        AHEM_WHY_AH_THANK_YOU_KIND_SIR_I                                      = 12738,  -- <Ahem> Why, ah--thank you, kind sir. I most certainly endeavor to be! As for the stockpile, we recently relocated it to--
        WAIT_A_MINUTE_I_VE_NOT_SEEN_YOUR                                      = 12739,  -- ...Wait a minute. I've not seen your faces before. Are you truly soldiers of the Allied Forces? State your affiliation!
        WE_FIGHT_FOR_THE_WAR_WARLOCKS_THE_MITHRA                              = 12740,  -- We fight for... The War Warlocks. The Mithra Mercenaries. The Future Fighters.
        I_SEE_AND_JUST_WHAT_SORT_OF_OUTFIT                                    = 12741,  -- I see... And just what sort of outfit might that be?
        OUR_DUTIES_ARE_TO_SLAY_OUR_FOES_WITH                                  = 12742,  -- Our duties are... To slay our foes with magic. To cut down enemies with our swords. To travel through time.
        IS_THAT_SO_AND_YOU_SAY_THAT_YOU                                       = 12743,  -- Is that so...? And you say that you serve the Allied Forces of Altana?
        YOU_SERVE_THE_ALLIED_FORCES_OUR_LIVES_FOR                             = 12744,  -- You serve the Allied Forces? Our lives for the Goddess! Yes, we're giving our all. Eh, more or less.
        I_ASK_YOU_HOW_DO_YOU_SUPPOSE_THIS                                     = 12745,  -- I ask you, how do you suppose this war will end?
        HOW_WILL_THE_GREAT_WAR_END_THE_ALLIED                                 = 12746,  -- How will the Great War end? The Allied Forces will triumph! The Beastman Confederate will prevail. How should I know?
        INDEED_AND_WHAT_DO_YOU_FEEL_HOLDS_THE                                 = 12747,  -- Indeed...and what do you feel holds the key to this conflict?
        THE_KEY_TO_THE_CONFLICT_IS_ROBEL_AKBEL                                = 12748,  -- The key to the conflict is... Robel-Akbel's true identity. The Shadow Lord's true identity. Our visitor from the future.
        INCIDENTALLY_WHY_IS_IT_THAT_YOU_SEEK_THE                              = 12749,  -- Incidentally, why is it that you seek the % and %?
        WHY_DO_YOU_NEED_THE_SUPPLIES_TO_SAVE                                  = 12750,  -- Why do you need the supplies? To save Windurst! To save the world! To save our future!
        VERY_WELL_THEN_I_CAN_SEE_THAT_YOU                                     = 12751,  -- Very well, then. I can see that you are loyal servants of Altana. Forgive me for having doubted you. One can never be too careful these days...
        THE_SUPPLIES_HAVE_BEEN_MOVED_TO_IN_PREPARATION                        = 12752,  -- The supplies have been moved to [/East Ronfaure/Jugner Forest/La Vaule] in preparation for any regional skirmishes that may arise. You are welcome to whatever you deem necessary for your cause.
        OH_AND_I_D_BE_REMISS_NOT_TO                                           = 12753,  -- Oh, and I'd be remiss not to tell you that they've been well hidden. Buried, actually. It wouldn't do to have them discovered by beastman curs, after all.
        ID_12754                                                              = 12754,  -- ...?
        DO_YOU_TAKE_ME_FOR_A_FOOL_BEGONE                                      = 12755,  -- Do you take me for a fool!? Begone, before I have you locked up like the rogues you are!
        MANY_THANKS_LOYAL_SOLDIER_MAY_THE_GODDESS_BE                          = 12756,  -- Many thanks, loyal soldier! May the Goddess be with you!
        WELL_IT_LOOKS_LIKE_WE_RE_MAKING_A                                     = 12757,  -- Well, %, it looks like we're making a detour to [/East Ronfaure/Jugner Forest/La Vaule]!
        VERY_WELL_I_SHALL_RETURN_TO_THE_FORT                                  = 12758,  -- Very well. I shall return to the fort and rrready our defenses.
        YES_BY_ALL_MEANS_LET_US_MAKE_HASTE                                    = 12759,  -- Yes, by all means. Let us make haste, %. We mustn't be late for the party!
        WE_VE_RELOCATED_THE_SUPPLIES_TO_SHOULD_YOU                            = 12760,  -- We've relocated the supplies to [/East Ronfaure/Jugner Forest/La Vaule]. Should you deem them necessary to your cause, you are welcome to them.
        I_HAVE_BEEN_STATIONED_HERE_TO_WATCH_OVER                              = 12761,  -- I have been stationed here to watch over the Allied Forces' supply of armaments. Move along, and keep your hands where they belong.
        DIALOGUE_DEBUG_POINTS                                                 = 12762,  -- Dialogue debug: # points.
        IF_YOU_WISH_TO_RIDE_A_CHOCOBO_YOU                                     = 12763,  -- If you wish to ride a chocobo, you must possess % and have a high enough job level.
