        QUIT_MISSION_YEAH_NO                                                  = 12816,  -- Quit mission? Yeah. No.
        CLEARED_USERWORK                                                      = 12817,  -- Cleared userwork.
        SET_DIFFICULTY_RANK_1_RANK_2_RANK_3                                   = 12818,  -- Set difficulty. Rank 1. Rank 2. Rank 3. Endless Debug Hell.
