        THAT_WILL_BE_ENOUGH_OFFICER_I_SHALL_COMPLETE                          = 12864,  -- That will be enough, officer. I shall complete the ceremony.
        SIR_LADY_I_COMMEND_YOU_ON_YOUR_SERVICE                                = 12865,  -- Sir/Lady] %, I commend you on your service to the Kingdom!
        BUT_REMEMBER_AS_YOU_ACCEPT_THIS_THE_PATH                              = 12866,  -- But remember, as you accept this %, the path before you grows ever more perilous. Succumb not to the evils of lethargy, lest you find yourself stripped bare of your past honors.
