        OH_AND_DON_T_GO_GETTING_THE_WRRRONG                                   = 12872,  -- Oh, and don't go getting the wrrrong idea. The reason you're wearing that medal isn't because you are a fine soldier, it's because you're backed by the best damn unit in the Federation. Dismissed!
        THAT_IS_ALL_PLEASE_NOTE_THAT_YOU_WILL                                 = 12873,  -- That is all. Please note that you will not be eligible for another evaluation for [five days/one hour] (Earth time). Good luck, %.
        ARE_YOU_CERTAIN_YOU_KNOW_THERE_IS_NO                                  = 12874,  -- Are you certain, %? You know there is no need to be humble.
        OR_PERHAPS_YOU_HAVE_FORGOTTEN_THAT_IT_DOESN                           = 12875,  -- Or perhaps you have forgotten that it doesn't matter how much you contribute to the Allied Campaign, you can only receive one medal per evaluation.
        I_CANNOT_FORCE_YOU_TO_ACCEPT_THE_MEDAL                                = 12876,  -- I cannot force you to accept the medal, but...
        WHILE_THE_ALLIED_WAR_COUNCIL_WAS_PLEASED_WITH                         = 12877,  -- While the Allied War Council was pleased with your work, it was determined that your performance did not warrant the conferral of further decoration.
