        EVEN_THE_PLATINUM_TICKETH_GOING_FOR_HUNDREDTH_OF                      = 13443,  -- Even the platinum ticketh going for hundredth of thouthandth of gil thold out in the blink of an eye.
        UNFORTUNATELY_WITHOUT_A_TICKET_YOU_THIMPLY_CANNOT_GET                 = 13444,  -- Unfortunately, without a ticket, you thimply cannot get into the thow. I'm thorry, but you'll jutht have to chalk it up to a lack of luck thith time.
        THEE_TO_IT_OUR_GUETHT_FINDTH_HITH_HER                                 = 13445,  -- Thee to it our guetht findth hith/her] way out, Gindaff!
        COME_OOON_WHEN_IS_THE_SHOW_GOING_TO                                   = 13446,  -- Come ooon, when is the show going to start? I can't wait...
        I_VE_BEEN_LOOKING_FORWARD_TO_THIS_FOR                                 = 13447,  -- I've been looking forward to this for weeks. And now that it's so close, I can barely contain myself! How much longer will it be?
        UNFORTUNATELY_OUR_REHEARSALS_HAVE_RUN_A_BIT_LONGER                    = 13448,  -- Unfortunately our rehearsals have run a bit longer than initially expected. The troupe asks that you remain patient for just a bit longer, and offers its sincerest apologies for any inconvenience.
        WELL_THIS_DOESN_T_LOOK_PROMISING_I_HAVE                               = 13449,  -- Well, this doesn't look promising. I have to get going soon...
        YOU_SCOUNDREL                                                         = 13450,  -- You scoundrel!
        AH_WH_WHAT_ARE_YOU_DOING_HERE                                         = 13451,  -- Ah! Wh-what are you doing here!?
        SO_THIS_IS_WHAT_WAS_SO_IMPORTANT_YOU                                  = 13452,  -- So this is what was so important you had to leave the shop? What is this? What's going on here?
        N_NOTHING_IT_S_JUST_SOME_WELL_THERE                                   = 13453,  -- N-nothing. It's just some... Well, there's this...
        WHAT_S_THAT_YOU_HAVE_THERE_A_TICKET                                   = 13454,  -- What's that you have there? A ticket? Troupe...Mayakov...?
        NO_NO_I_HAVE_NO_IDEA_WHAT_THAT                                        = 13455,  -- No, no! I have no idea what that is! I didn't do anything! I admit nothing!
        I_KNEW_YOU_WERE_UP_TO_SOMETHING_ACTING                                = 13456,  -- I knew you were up to something, acting all shady like you were! And look at you now! Skipping work and leaving the shop unattended to come to a place like this!
        WELL_IF_YOU_DON_T_GET_BACK_TO                                         = 13457,  -- Well, if you don't get back to work, there'll be no dinner tonight! Or any other night for that matter!
