        YOU_DO_NOT_HAVE                                                       = 13459,  -- You do not have %!
        YOU_AGAIN_QUITE_THE_PERTHITHTENT_ONE_AREN_T                           = 13460,  -- You, again? Quite the perthithtent one, aren't you? Thome people never learn, I thuppothe.
        HM_YOU_BROUGHT_A_TICKET_WITH_YOU_THITH                                = 13461,  -- Hm? You brought a ticket with you thith time? Let'th have a look at it, then.
        WHAT_THE                                                              = 13462,  -- What the...
        EWWW_IT_LOOKS_AS_THOUGH_IT_S_BEEN                                     = 13463,  -- Ewww... It looks as though it's been through hell and back! Do I even want to know what happened to that ticket?
