        IT_BEGINS                                                             = 13496,  -- It begins!
        GREETINGS_TO_ALL_AND_A_HEARTFELT_THANK_YOU                            = 13497,  -- Greetings to all, and a heartfelt thank you on behalf of the troupe for gracing us with your presence tonight. And without further delay, on to the evening's presentation!
        COME_NOW_AND_BEHOLD_A_FAIR_DANCE_BE                                   = 13498,  -- Come now, and behold a fair dance, Be moved to dream, in deep waking trance!t
        PAUPER_SAGE_EVEN_THE_NOBLEMAN_KNOWS_ALL_ARE                           = 13499,  -- Pauper, sage, even the nobleman knows, All are welcomed, with warmth, by Troupe Mayakov!t Old hag, young beauty, even the sweet child knows, All are embraced, with love, by Troupe Mayakov!t
        SEVER_TIES_FETTERED_FOOL_AND_MAKE_MERRY_THIS                          = 13500,  -- Sever ties, fettered fool, and make merry this night! Come now, honored guests, and forget all this night!t
        FOR_THE_DARK_STILL_YOUNG_SWALLOWED_THE_SUN                            = 13501,  -- For the dark, still young, swallowed the sun what once shone, And the time to revel is this night, and now alone!t
