        SEE_DIDN_T_I_TELL_YOU_A_GROUP                                         = 13503,  -- See? Didn't I tell you? A group of lookers all!
        YOU_BETTER_NOT_EVEN_THINK_ABOUT_MAKING_A                              = 13504,  -- You better not even think about making a move on the one all the way on the right, though. I've got my sights set on her! Don't make me pull rank on you!
