        IF_YOU_LL_EXCUSE_ME_I_HAVE_SOME                                       = 13527,  -- If you'll excuse me, I have some minor business I must see to.
        I_M_SURE_THAT_OUR_PATHS_WILL_CROSS                                    = 13528,  -- I'm sure that our paths will cross again. We are on the same side, after all. Farewell for now.
        HOW_FARE_THINGS_IN_LA_VAULE                                           = 13529,  -- How fare things in La Vaule?
        SIR_ACCORDING_TO_INTELLIGENCE_REPORTS_FROM_THE_LATEST                 = 13530,  -- Sir, according to intelligence reports from the latest courier, ranks are currently regrouping at that location.
        THE_KNIGHTS_OF_THE_MADDER_FALCON_REPORT_TO                            = 13531,  -- The Knights of the Madder Falcon report to be rebuilding the defenses and barricading strategic points. The resistance, however, continues in waves...
