        FIRST_LESSON_OF_THE_DAY_A_SOLDIER_S                                   = 14150,  -- First lesson of the day: a soldier's worth is measured by his/her] actions, not words. Now, go and fetch me %, posthaste!
        I_SAID_HAVE_YOU_SAWDUST_FOR_BRAINS_MAKE                               = 14151,  -- %, I said! Have you sawdust for brains? Make me repeat myself once more, and your pouting lips will find themselves at odds with my gauntlet!
        HM_SO_YOU_VE_SOMEHOW_MANAGED_TO_FIND                                  = 14152,  -- Hm? So you've somehow managed to find %. Not bad...for a worthless maggot.
        WHERE_S_MY_SIGNATURE_YOU_SAY_HAH_I                                    = 14153,  -- Where's my signature, you say? Hah! I withdraw my behemoth hide comment. Why, you're thicker than one of Tavnazia's defensive walls!
        EYES_FRONT_NEXT_IN_THE_ORDER_OF_BUSINESS                              = 14154,  -- Eyes front! Next in the order of business: RPS training!
        HM_HAVEN_T_HAD_ENOUGH_PAIN_YOU_SAY                                    = 14155,  -- Hm? Haven't had enough pain, you say? In that case, I'd be happy to oblige! We shall pick things up from the %...
        IS_WHAT_I_WOULD_SAY_ORDINARILY_BUT_I                                  = 14156,  -- ...Is what I would say ordinarily, but I haven't anymore of my precious time to waste on a single, squirming maggot.
        WE_SHALL_RESUME_FROM_THE_RPS_TRAINING_KEEP                            = 14157,  -- We shall resume from the RPS training. Keep your posture ram-rod straight, and your mind on high alert. Eyes front!
        DO_YOU_NEED_EVERYTHING_TO_BE_SPELLED_OUT                              = 14158,  -- Do you need everything to be spelled out for you? Alternatively, if you intend to scamper off with your tail between your legs, now's the time.
        DO_YOU_REQUIRE_AN_EXPLANATION_NO_THANK_YOU                            = 14159,  -- Do you require an explanation? No, thank you. Yes, please.
        RPS_IS_A_REVOLUTIONARY_TRAINING_METHOD_DEVELOPED_BY                   = 14160,  -- RPS is a revolutionary training method developed by the Kingdom, for the Kingdom. The R stands for Rock, the P stands for Phantom, and the S stands for Scorpion.
        IN_THIS_TRAINING_YOU_MUST_CHOOSE_FROM_ONE                             = 14161,  -- In this training, you must choose from one of the following to use as your weapon:
