        I_ON_THE_OTHER_HAND_WILL_UNLEASH_A                                    = 14163,  -- I, on the other hand, will unleash a ferocious monster upon you.
        TIS_UNFORTUNATE_AND_TAKES_AWAY_FROM_THE_THRILL                        = 14164,  -- 'Tis unfortunate and takes away from the thrill, I know, but the monsters I produce will be mere illusions. You shan't be requiring diapers.
