        YOU_VE_AND                                                            = 14180,  -- You've # [win/wins] and # [defeat/defeats].
        R_P_S                                                                 = 14181,  -- R`P`S!
        CHOOSE_YOUR_WEAPON_VOLCANIC_ROCK_NETHER_VELLUM_SCORPION               = 14182,  -- Choose your weapon! Volcanic rock. Nether vellum. Scorpion stinger.
        NOT_BAD_MAGGOT_NOT_BAD_BUT_THE_FIGHT                                  = 14183,  -- Not bad, maggot! Not bad! But the fight isn't over yet!
