        FOOL_WERE_YOU_PAYING_ANY_ATTENTION_TO_MY                              = 14185,  -- Fool! Were you paying any attention to my movements?
        YOU_DISAPPOINT_ME_MAGGOT_GO_REFLECT_ON_YOUR                           = 14186,  -- You disappoint me, maggot! Go reflect on your failure and return when you've unraveled the true essence of RPS!
