        I_AM_A_VOIDWATCH_OFFICER_DISPATCHED_HERE_BY                           = 15336,  -- I am a Voidwatch officer dispatched here by the [Grand Duchy of Jeuno/Allied Forces of Altana]. My duty is to recruit able-bodied soldiers to assist in repelling the Voidwalker threat.
        I_BESEECH_YOU_FRIEND_LEND_YOUR_AID_TO                                 = 15337,  -- I beseech you, friend. Lend your aid to our cause, lest our fair Vana'diel be engulfed in fire and brimstone.
        WHAT_WILL_YOU_DO_NOTHING_FOR_NOW_ASK                                  = 15338,  -- What will you do? Nothing for now. Ask a bunch of questions. Participate in Voidwatch Ops. Request debriefing. Request %. Check voidstone stock. Request reward issuance.
        WHILE_I_COMMEND_YOUR_ENTHUSIASM_ONLY_THOSE_WHO                        = 15339,  -- While I commend your enthusiasm, only those who possess % may participate in Voidwatch Ops.
        THE_IS_CONSIDERED_PROOF_OF_ONE_S_VALOR                                = 15340,  -- The % is considered proof of one's valor and prowess, and is awarded only to those who have distinguished themselves in the three nations.
        ENLISTED_IN_S_ARMED_FORCES_YOU_SAY_HMM                                = 15341,  -- Enlisted in [San d'Oria/Bastok/Windurst]'s armed forces, you say? Hmm... There appears to be no record of your service there.
        I_M_SORRY_BUT_ONLY_THOSE_WITH_MILITARY                                = 15342,  -- I'm sorry, but only those with military affiliation may participate in Voidwatch Ops.
        WHILE_YOUR_ENTHUSIASM_IS_HEARTENING_THE_VOIDWATCH_REQUIRES            = 15343,  -- While your enthusiasm is heartening, the Voidwatch requires men and women of tested steel. Come back again once you have proven your worth.
        YOU_MUST_BE_AT_LEAST_LEVEL_TO_PARTICIPATE                             = 15344,  -- You must be at least level # to participate in Voidwatch.
        HAVE_A_MIND_TO_LEND_US_YOUR_AID                                       = 15345,  -- Have a mind to lend us your aid? Splendid!
        I_SEE_YOU_VE_YET_TO_BE_ISSUED                                         = 15346,  -- I see you've yet to be issued %. Here, take this and keep it on your person at all times.
        STRATUM_ABYSSITE_IS_NEEDED_TO_DO_BATTLE_WITH                          = 15347,  -- Stratum abyssite is needed to do battle with a Voidwalker at one of the many planar rifts that have manifested across the land.
        YOU_CAN_T_SIMPLY_USE_ONE_WHEREVER_YOU                                 = 15348,  -- You can't simply use one wherever you like, mind you, for each stone is attuned only to rifts found in a certain region, or jurisdiction.
        UNDERTAKING_A_VOIDWATCH_OPERATION_IN_A_SPECIFIC_JURISDICTION          = 15349,  -- Undertaking a Voidwatch operation in a specific jurisdiction requires that you obtain the corresponding stone from the presiding Voidwatch officer.
        WHILE_THESE_STONES_ARE_CAPABLE_OF_RENDERING_VOIDWALKERS               = 15350,  -- While these stones are capable of rendering Voidwalkers visible to their bearers, their powers can only be tapped when used in conjunction with %.
        OPERATIONS_ARE_PRESENTLY_UNDERWAY_AT_WHILE_PLANAR_RIFTS               = 15351,  -- Operations are presently underway at [East Ronfaure/East Ronfaure/Ordelle's Caves/the Jugner Forest/the Jugner Forest/King Ranperre's Tomb/West Ronfaure/La Theine Plateau/Vunkerl Inlet]. While planar rifts have been reported in other areas, we've yet to discover how to engage Voidwalkers there.
        OPERATIONS_ARE_PRESENTLY_UNDERWAY_AT_WHILE_PLANAR_RIFTS_2             = 15352,  -- Operations are presently underway at [North Gustaberg/North Gustaberg/the Gusgen Mines/the Pashhow Marshlands/the Pashhow Marshlands/Dangruf Wadi/South Gustaberg/the Konschtat Highlands/Grauberg]. While planar rifts have been reported in other areas, we've yet to discover how to engage Voidwalkers there.
        OPERATIONS_ARE_PRESENTLY_UNDERWAY_AT_WHILE_PLANAR_RIFTS_3             = 15353,  -- Operations are presently underway at [West Sarutabaruta/West Sarutabaruta/the Maze of Shakhrami/the Meriphataud Mountains/the Meriphataud Mountains/the Outer Horutoto Ruins/East Sarutabaruta/Tahrongi Canyon/Fort Karugo-Narugo]. While planar rifts have been reported in other areas, we've yet to discover how to engage Voidwalkers there.
        IT_WOULD_SEEM_SOME_OTHER_REQUIREMENT_EXISTS_BESIDES                   = 15354,  -- It would seem some other requirement exists besides the usual % and %.
        REST_ASSURED_YOU_WILL_BE_APPRISED_OF_THIS                             = 15355,  -- Rest assured, you will be apprised of this information as soon as we acquire it.
        AT_THIS_TIME_WE_REQUEST_YOUR_PARTICIPATION_IN                         = 15356,  -- At this time, we request your participation in the operation at [East Ronfaure/East Ronfaure/Ordelle's Caves/the Jugner Forest/the Jugner Forest/King Ranperre's Tomb/West Ronfaure/La Theine Plateau/Vunkerl Inlet].
        AT_THIS_TIME_WE_REQUEST_YOUR_PARTICIPATION_IN_2                       = 15357,  -- At this time, we request your participation in the operation at [North Gustaberg/North Gustaberg/the Gusgen Mines/the Pashhow Marshlands/the Pashhow Marshlands/Dangruf Wadi/South Gustaberg/the Konschtat Highlands/Grauberg].
        AT_THIS_TIME_WE_REQUEST_YOUR_PARTICIPATION_IN_3                       = 15358,  -- At this time, we request your participation in the operation at [West Sarutabaruta/West Sarutabaruta/the Maze of Shakhrami/the Meriphataud Mountains/the Meriphataud Mountains/the Outer Horutoto Ruins/East Sarutabaruta/Tahrongi Canyon/Fort Karugo-Narugo].
        WHEN_YOU_ENGAGE_IN_BATTLE_WITH_A_VOIDWALKER                           = 15359,  -- When you engage in battle with a Voidwalker, you do so as a Voidwatcher--a defender of our dimension. The rules of such engagements are unlike any other, and I counsel you to proceed prepared and with all caution.
        NOW_GO_AND_DO_VANA_DIEL_PROUD                                         = 15360,  -- Now, go and do Vana'diel proud!
        AH_THERE_S_ONE_THING_THAT_SHOULD_BE                                   = 15361,  -- Ah, there's one thing that should be of interest to you.
        THE_YOU_POSSESS_OUR_RESEARCHERS_HAVE_DISCOVERED_A                     = 15362,  -- The % you possess--our researchers have discovered a most intriguing property about it.
        YOU_SEE_THIS_PARTICULAR_VARIETY_OF_ABYSSITE_IS                        = 15363,  -- You see, this particular variety of abyssite is known to absorb the energy released by felled Voidwalkers. Not any of the creatures, mind you, but only those drawn to planar rifts.
        ABSORBING_THIS_ENERGY_CAUSES_THE_ABYSSITE_TO_EVOLVE                   = 15364,  -- Absorbing this energy causes the abyssite to evolve, or more accurately, makes it attuned to other planar rifts. This, of course, translates to an expanded sphere of Voidwatch Ops in which the bearer may participate.
        YOUR_PRESENCE_THERE_WOULD_BE_OF_TREMENDOUS_AID                        = 15365,  -- [Operations are set to commence at/Operations are currently underway at] [East Ronfaure/East Ronfaure/Ordelle's Caves/the Jugner Forest/the Jugner Forest/King Ranperre's Tomb/West Ronfaure/La Theine Plateau/Vunkerl Inlet]. Your presence there would be of tremendous aid to our efforts.
        YOUR_PRESENCE_THERE_WOULD_BE_OF_TREMENDOUS_AID_2                      = 15366,  -- [Operations are set to commence at/Operations are currently underway at] [North Gustaberg/North Gustaberg/the Gusgen Mines/the Pashhow Marshlands/the Pashhow Marshlands/Dangruf Wadi/South Gustaberg/Konschtat Highlands/Grauberg]. Your presence there would be of tremendous aid to our efforts.
        YOUR_PRESENCE_THERE_WOULD_BE_OF_TREMENDOUS_AID_3                      = 15367,  -- [Operations are set to commence at/Operations are currently underway at] [West Sarutabaruta/West Sarutabaruta/the Maze of Shakhrami/the Meriphataud Mountains/the Meriphataud Mountains/the Outer Horutoto Ruins/East Sarutabaruta/Tahrongi Canyon/Fort Karugo-Narugo]. Your presence there would be of tremendous aid to our efforts.
        OPERATIONS_ARE_CURRENTLY_UNDERWAY_YOUR_PRESENCE_THERE_WOULD           = 15368,  -- Operations are currently underway [in the greater Jeuno region/in the three nations]. Your presence there would be of tremendous aid to our efforts.
        AH_I_DARESAY_YOUR_HAS_UNDERGONE_CHANGE                                = 15369,  -- Ah, I daresay your % has undergone change!
        HOW_MANY_WOULD_YOU_LIKE_NONE_JUST_ONE                                 = 15370,  -- How many would you like? None. Just one. Fill me up!
        HERE_IS_YOUR_ADDITIONAL_ALLOCATION_MAKE_EACH_AND                      = 15371,  -- Here is your additional % allocation. Make each and every one count, you hear?
        IT_APPEARS_YOU_ALREADY_POSSESS_THE_MAXIMUM_ALLOCATION                 = 15372,  -- It appears you already possess the maximum allocation of # stones. I'm not authorized to provision you with more.
        I_M_AFRAID_WE_RE_OUT_OF_STOCK                                         = 15373,  -- I'm afraid we're out of stock. The next shipment is expected to arrive in # [minute/minutes] (Earth time).
        OBTAINED_KEY_ITEM_4                                                   = 15374,  -- Obtained key item: # %!
        OBTAINED_KEY_ITEM_5                                                   = 15375,  -- Obtained key item: # %!
        YOUR_OUTSTANDING_ALLOCATION_OF_MY_RECORDS_TELL_ME                     = 15376,  -- Your outstanding allocation of %? My records tell me you have # to your name.
        EXCHANGE_FOR_WHAT_CRUOR_NOTHING_RIGHT_NOW                             = 15377,  -- Exchange for what? (Cruor: #) Nothing right now. %: #. %: #. %: #. %: #. %: #. %: #. %: #. %: #. %: #. %: #. %: #. %: #. %: #. %: #. %: #. %: #.
        CRUOR_IS_REQUIRED_FOR                                                 = 15378,  -- # cruor is required for %.
        CRUOR_IS_REQUIRED_FOR_THE                                             = 15379,  -- # cruor is required for the %.
        PROCEED_REQUIRED_CRUOR_YES_NO                                         = 15380,  -- Proceed? (Required Cruor: #) Yes. No.
        IT_SEEMS_YOU_DO_NOT_HAVE_ENOUGH_CRUOR                                 = 15381,  -- It seems you do not have enough cruor.
        HANDS_OVER_CRUOR_IN_EXCHANGE_FOR                                      = 15382,  -- % hands over # cruor in exchange for %!
        HANDS_OVER_CRUOR_IN_EXCHANGE_FOR_THE                                  = 15383,  -- % hands over # cruor in exchange for the %!
        HM_IT_SEEMS_YOU_ALREADY_POSSESS_IN_THAT                               = 15384,  -- Hm? It seems you already possess %. In that case, you won't be needing another.
        THIS_PERIAPT_ALLOWS_THE_BEARER_TO_INFUSE_AN                           = 15385,  -- This periapt allows the bearer to infuse an additional atmacite for each one possessed.
        THIS_PERIAPT_GRANTS_THE_BEARER_HEIGHTENED_INSIGHT_INTO                = 15386,  -- This periapt grants the bearer heightened insight into Voidwalker weaknesses against weapon skills and abilities.
        THIS_PERIAPT_GRANTS_THE_BEARER_HEIGHTENED_INSIGHT_INTO_2              = 15387,  -- This periapt grants the bearer heightened insight into Voidwalker weaknesses against magic.
        THIS_PERIAPT_ENHANCES_THE_EFFECT_GRANTED_BY_A                         = 15388,  -- This periapt enhances the effect granted by a periapt of guidance.
        THIS_PERIAPT_ENHANCES_THE_EFFECT_GRANTED_BY_A_2                       = 15389,  -- This periapt enhances the effect granted by a periapt of percipience.
        A_BEWITCHING_LIGHT_SHINES_FORTH_FROM_WITHIN_THE                       = 15390,  -- A bewitching light shines forth from within the crystallized walls of this fragment ripped from a Voidwalker, as if beckoning its bearer to come hither.
        A_TANTALIZING_LIGHT_SHINES_FORTH_FROM_WITHIN_THE                      = 15391,  -- A tantalizing light shines forth from within the crystallized walls of this fragment ripped from a Voidwalker, as if appealing to its bearer's most ardent desires.
        A_CRAZED_LIGHT_SHINES_FORTH_FROM_WITHIN_THE                           = 15392,  -- A crazed light shines forth from within the crystallized walls of this fragment ripped from a Voidwalker, as if seeking to breach the bearer's last bastion of sanity.
        WHAT_WILL_YOU_ASK_ABOUT_NOTHING_THE_VOIDWALKER                        = 15393,  -- What will you ask about? Nothing. The Voidwalker threat. How I can do my part. The Voidwatch. Voidwatchers. Ascent items. Riftworn pyxides. %. Stratum abyssite. Planar rifts. Cruor. Abyssite. Voidstone consumption.
        VOIDWALKER_IS_THE_NAME_GIVEN_TO_CREATURES_THAT                        = 15394,  -- Voidwalker is the name given to creatures that roam the realm between worlds.
        LITTLE_IS_KNOWN_ABOUT_THEM_AT_THIS_TIME                               = 15395,  -- Little is known about them at this time, except that they're driven by an insatiable lust for destruction.
        WHILE_REPORTS_OF_VOIDWALKER_ENCOUNTERS_VARY_GREATLY_IN                = 15396,  -- While reports of Voidwalker encounters vary greatly in content, one thing is certain: the creatures are gaining in strength, a mounting threat that cannot be left unchecked.
        IN_OUR_EFFORT_TO_NEUTRALIZE_THE_VOIDWALKER_MENACE                     = 15397,  -- In our effort to neutralize the Voidwalker menace, the Voidwatch is petitioning adventurers to lend their aid.
        AS_THE_NATURE_OF_VOIDWALKER_BATTLES_RENDERS_FULL                      = 15398,  -- As the nature of Voidwalker battles renders full-scale military operations unfeasible, we have chosen to stake our success on the mobility and versatility of adventurers.
        IN_OUR_EFFORT_TO_NEUTRALIZE_THE_VOIDWALKER_MENACE_2                   = 15399,  -- In our effort to neutralize the Voidwalker menace, the Voidwatch is petitioning soldiers of the Allied Forces to lend their aid.
        TO_BE_SURE_THERE_RE_THOSE_WHO_QUESTION                                = 15400,  -- To be sure, there're those who question the wisdom of thinning our ranks in the face of the Shadow Lord's armies. But I assure you, friend, the Voidwalker threat is no less real.
        OUR_SCOUTS_REGULARLY_BRING_BACK_INTEL_ON_LOCATIONS                    = 15401,  -- Our scouts regularly bring back intel on locations of suspected Voidwalker presence.
        ARMED_WITH_THIS_INFORMATION_WE_DISPATCH_STRIKE_TEAMS                  = 15402,  -- Armed with this information, we dispatch strike teams to preemptively neutralize the threat.
        ORDINARILY_VOIDWALKERS_CANNOT_BE_SEEN_LET_ALONE_FOUGHT                = 15403,  -- Ordinarily, Voidwalkers cannot be seen, let alone fought. Only by using the voidstone's power can we force them to feel the sting of our steel.
        THESE_MAGICKED_STONES_ARE_DISTRIBUTED_IN_REGULAR_SHIPMENTS            = 15404,  -- These magicked stones are distributed in regular shipments from our Jeuno-based research team. They're the bare minimum we need to have a fighting chance against the enemy.
        VOIDSTONES_WORK_BY_REALIGNING_YOUR_EXISTENTIAL_SPECTRUM_TO            = 15405,  -- Voidstones work by realigning your existential spectrum to match that of Voidwalkers, thus rendering the creatures visible to you.
        THE_STONES_ARE_HIGHLY_PRIZED_SUCH_IS_THE                              = 15406,  -- The stones are highly prized, such is the difficulty of their creation. As such, supplies are limited to # stones per person at any given time.
        THAT_S_PROVIDED_WE_HAVE_ANY_IN_STOCK                                  = 15407,  -- That's provided we have any in stock at all. Much time is required in imbuing them with requisite powers.
        THE_VOIDWATCH_IS_AN_ORGANIZATION_THAT_EXISTS_FOR                      = 15408,  -- The Voidwatch is an organization that exists for the sole purpose of protecting the world from extradimensional invaders we call Voidwalkers.
        RECOGNIZING_THE_GRAVENESS_OF_THIS_THREAT_THE_NATIONS                  = 15409,  -- Recognizing the graveness of this threat, the nations of the Middle Lands joined together in common cause and formed the Voidwatch.
        HELMING_THE_ORGANIZATION_IS_THE_GRAND_DUCHY_OF                        = 15410,  -- Helming the organization is the Grand Duchy of Jeuno, with the remaining three nations contributing resources for its operation.
        POSSESSION_OF_IS_A_REQUIREMENT_FOR_PARTICIPATING_IN                   = 15411,  -- Possession of % is a requirement for participating in Voidwatch Ops.
        IT_CAN_BE_EARNED_ONLY_THROUGH_LOYAL_SERVICE                           = 15412,  -- It can be earned only through loyal service to your nation, and thus serves as a testimonial for your prowess.
        YOU_WOULD_DO_WELL_TO_OBTAIN_ONE_IF                                    = 15413,  -- You would do well to obtain one if you haven't already done so.
        AFFILIATION_WITH_THE_ALLIED_FORCES_OF_ALTANA_IS                       = 15414,  -- Affiliation with the Allied Forces of Altana is a requirement for participating in Voidwatch Ops.
        IN_OTHER_WORDS_YOU_MUST_BELONG_TO_THE                                 = 15415,  -- In other words, you must belong to the armed forces of one of the three nations.
        THE_ENLISTMENT_PROCEDURE_VARIES_DEPENDING_ON_NATION_THOSE             = 15416,  -- The enlistment procedure varies depending on nation. Those wishing to obtain a recommendation letter should pay visit to one of the military encampments surrounding Jeuno.
        WHEN_YOU_BATTLE_A_VOIDWALKER_YOU_MUST_DO                              = 15417,  -- When you battle a Voidwalker, you must do so as a Voidwatcher--a defender of the dimension who has harnessed the powers of the voidstone and stratum abyssite.
        BEREFT_OF_THESE_TWO_OBJECTS_VOIDWALKERS_CANNOT_BE                     = 15418,  -- Bereft of these two objects, Voidwalkers cannot be seen, let alone fought.
        HOWEVER_THERE_ARE_A_FEW_POINTS_ALL_BUDDING                            = 15419,  -- However, there are a few points all budding Voidwatchers should bear in mind.
        MOST_CRUCIAL_OF_ALL_THE_EXTRADIMENSIONAL_NATURE_OF                    = 15420,  -- Most crucial of all, the extradimensional nature of being a Voidwatcher renders you isolated and unable to receive help from the outside world.
        SCIENTISTS_ATTRIBUTE_THIS_TO_THE_DIMENSIONAL_MISALIGNMENT_THAT        = 15421,  -- Scientists attribute this to the dimensional misalignment that occurs. As people are ordinarily unable to see Voidwalkers, so too are they unable to see you.
        BUT_YOU_NEEDN_T_CONCERN_YOURSELF_WITH_THE                             = 15422,  -- But you needn't concern yourself with the hows and whys of such matters. It would behoove you far more to become familiar with the workings of the existential spectrum.
        YOU_SEE_EACH_DIMENSION_IS_COMPOSED_OF_AN                              = 15423,  -- You see, each dimension is composed of an existential spectrum to which all things within are aligned. In turn, the spectrum is formed of five lights: blue, red, yellow, green, and white.
        THE_ALIGNMENT_OF_THESE_LIGHTS_BETWEEN_VOIDWALKER_AND                  = 15424,  -- The alignment of these lights between Voidwalker and Voidwatcher plays an important role in our efforts.
        TO_ELABORATE_THE_ACT_OF_RENDERING_A_VOIDWALKER                        = 15425,  -- To elaborate, the act of rendering a Voidwalker visible is essentially an act of aligning ourselves to its existential spectrum.
        NOW_WHILE_VOIDWATCHERS_ARE_ABLE_TO_FOR_ALL                            = 15426,  -- Now, while Voidwatchers are able to, for all practical purposes, interact with these creatures, they in fact fall short of full alignment. Symptoms of this imperfect state can be observed in the limited quantity and quality of spoils normally yielded by Voidwalkers.
        COMPENSATING_MEASURES_HOWEVER_HAVE_BEEN_DEVELOPED_TO_ALLOW            = 15427,  -- Compensating measures, however, have been developed to allow combatants to more closely attune themselves with their extradimensional foe.
        ONE_SUCH_METHOD_INVOLVES_THE_USE_OF_ALIGNMENT                         = 15428,  -- One such method involves the use of alignment-enhancing artifacts known as ascent items, while another entails performing certain actions against the enemy.
        BOTH_METHODS_AIM_TO_MANIPULATE_THE_ALIGNMENT_VALUE                    = 15429,  -- Both methods aim to manipulate the alignment value of individual lights to various ends.
        ALL_FIVE_LIGHTS_INFLUENCE_THE_CONTENTS_OF_THE                         = 15430,  -- All five lights influence the contents of the treasure chest which appears at the successful end of battle.
        OUR_RESEARCHERS_HAVE_SUCCEEDED_IN_DETERMINING_WHAT_MANNER             = 15431,  -- Our researchers have succeeded in determining what manner of benefits are associated with each light.
        FOR_INSTANCE_IMPROVING_BLUE_SPECTRAL_ALIGNMENT_IS_KNOWN               = 15432,  -- For instance, improving blue spectral alignment is known to produce greater quantities of spoils.
        IN_CONTRAST_MANIPULATING_RED_SPECTRAL_ALIGNMENT_REPORTEDLY_ENHANCES   = 15433,  -- In contrast, manipulating red spectral alignment reportedly enhances the quality of individual items--potions becoming hi-potions, and so forth.
        YELLOW_AND_GREEN_ON_THE_OTHER_HAND_INFLUENCE                          = 15434,  -- Yellow and green, on the other hand, influence experience gain and cruor yield respectively.
        IF_YOU_WISH_TO_KNOW_MORE_ABOUT_THE                                    = 15435,  -- If you wish to know more about the curious red substance we call cruor, you need but ask.
        LASTLY_WE_HAVE_WHITE_SPECTRAL_ALIGNMENT_WHICH_IS                      = 15436,  -- Lastly, we have white spectral alignment, which is unique even in this company. It has been determined to affect the appearance of transdimensional objects such as atmacite and periapt.
        RESEARCH_REGARDING_THESE_ARTIFACTS_IS_STILL_ONGOING                   = 15437,  -- Research regarding these artifacts is still ongoing.
        LASTLY_BE_REASSURED_THAT_THERE_RE_NO_KNOWN                            = 15438,  -- Lastly, be reassured that there're no known negative effects of manipulating spectral alignment. We unreservedly encourage all Voidwatch operatives to endeavor towards maximum alignment.
        ASCENT_ITEMS_ARE_UNIQUE_OBJECTS_THAT_CAN_BE                           = 15439,  -- Ascent items are unique objects that can be used to manipulate the spectral alignment of corresponding lights in the existential spectrum.
        AND_ARE_REPRESENTATIVE_OF_SUCH_ITEMS_THEY_RE                          = 15440,  -- % and % are representative of such items. They're the pride and joy of our Jeuno-based research team, who'd have folk believe they're the greatest inventions since airships.
        JUST_BETWEEN_YOU_AND_ME_THOUGH_IT_IS                                  = 15441,  -- (Just between you and me, though, it is Far Eastern scientists that pioneered the technology they're based upon.)
        THEY_RE_NOT_THE_ONLY_MEANS_BY_WHICH                                   = 15442,  -- They're not the only means by which we manipulate spectral alignment, mind you. Similar results can be achieved by performing specific actions against the enemy.
        TRUTH_BE_TOLD_MUCH_IS_STILL_SHROUDED_IN                               = 15443,  -- Truth be told, much is still shrouded in mystery. What actions will produce the desired effect is something you will have to discover for yourself through trial and error.
        DEFEATING_A_VOIDWALKER_WILL_CAUSE_A_MYSTERIOUS_PYXIS                  = 15444,  -- Defeating a Voidwalker will cause a mysterious pyxis to emerge at the selfsame planar rift whence the creature was felled.
        SUCH_RIFTWORN_PYXIDES_EXHIBIT_A_MOST_PECULIAR_CHARACTERISTIC          = 15445,  -- Such riftworn pyxides exhibit a most peculiar characteristic: the content they bear reportedly changes depending on who glimpses within.
        OUR_SCIENTISTS_CONJECTURE_THAT_THIS_IS_DUE_TO                         = 15446,  -- Our scientists conjecture that this is due to some trick of spectral alignment. As with numerous other mysteries surrounding Voidwalkers, however, I highly doubt they have even an inkling of understanding. But I digress...
        ONLY_ONE_COMBATANT_NEED_POSSESS_A_VOIDSTONE_FOR                       = 15447,  -- Only one combatant need possess a voidstone for all party or alliance members to do battle with a Voidwalker. Of the other squad members only stratum abyssite is required.
        AS_ALWAYS_SEEMS_TO_BE_THE_CASE_HOWEVER                                = 15448,  -- As always seems to be the case, however, there is a catch. Pyxides have been observed to yield less spoils for combatants without a voidstone of their own.
        IT_SCARCE_NEEDS_BE_SAID_BUT_IT_WOULD                                  = 15449,  -- It scarce needs be said, but it would be to your benefit to have both the aforementioned items readied before taking on a Voidwalker.
        LASTLY_A_WARNING_PYXIDES_WILL_EVENTUALLY_VANISH_IF                    = 15450,  -- Lastly, a warning: pyxides will eventually vanish if left untouched overlong. Our scientists have put forth the theory of normalizing spatial dissonance, but you needn't concern yourself with their mumbo-jumbo.
        JUST_SEE_TO_IT_THAT_YOUR_HARD_EARNED                                  = 15451,  -- Just see to it that your hard-earned spoils are claimed in good time, and things will be rosy for all involved.
        THE_IS_A_MAGICKED_OBJECT_PRODUCED_BY_THE                              = 15452,  -- The % is a magicked object produced by the Voidwatch's Jeuno-based research wing.
        ITS_INNOCUOUS_APPEARANCE_BELIES_THE_IMMENSE_POWER_IT                  = 15453,  -- Its innocuous appearance belies the immense power it holds...the power to render Voidwalkers visible to its bearer.
        THE_STONE_ACHIEVES_THIS_FEAT_BY_REALIGNING_OUR                        = 15454,  -- The stone achieves this feat by realigning our existential spectrum to that of the creature.
        I_SHALL_EXPLAIN_THE_PROCESS_IN_LAYMAN_S                               = 15455,  -- I shall explain the process in layman's terms for your benefit. No need to thank me--I merely perform my duty.
        I_WANT_YOU_TO_VISUALIZE_TWO_CANVASES_EACH                             = 15456,  -- I want you to visualize two canvases, each the same distance from the other. Yes, as two separate objects are normally wont to be.
        IMAGINE_YOU_AND_I_STANDING_ON_ONE_OF                                  = 15457,  -- Imagine you and I standing on one of the canvases--what else does one do with a canvas but stand on it, yes?
        NOW_IMAGINE_VOIDWALKERS_STANDING_ON_THE_OTHER_CANVAS                  = 15458,  -- Now, imagine Voidwalkers standing on the other canvas, doing whatever it is Voidwalkers do. Destroying things and behaving with utter impropriety, no doubt.
        BEING_ON_TWO_DIFFERENT_CANVASES_IT_FOLLOWS_THAT                       = 15459,  -- Being on two different canvases, it follows that we cannot touch the Voidwalkers, let alone see them. Actually, that doesn't explain why we can't see the Voidwalkers...unless it's a magical canvas they're on that makes all things upon it invisible! Yes, that'll serve!
        AND_THIS_BRINGS_US_FULL_CIRCLE_BACK_TO                                = 15460,  -- And this brings us full circle back to the voidstone. I want you to think of it as a magical paintbrush that we use to...grapple ourselves over to the Voidwalkers' canvas. Thence the fighting begins.
        I_TRUST_YOU_NOW_HAVE_A_RUDIMENTARY_UNDERSTANDING                      = 15461,  -- I trust you now have a rudimentary understanding of the process. That's all you need, really. Leave the fractal geometry to the fractal geometrists, I always say.
        AS_LONG_AS_YOU_REMEMBER_THE_CANVAS_AND                                = 15462,  -- As long as you remember the canvas and the paintbrush--that's the voidstone--you cannot go astray. Now, to apprise you of more practical matters...
        TWENTY_HOURS_EARTH_TIME_IS_REQUIRED_TO_PRODUCE                        = 15463,  -- Twenty hours (Earth time) is required to produce a stone and imbue it with the necessary magicks, although word is that this may be shortened as research progresses.
        MIND_YOU_THIS_ISN_T_THE_ONLY_VARIETY                                  = 15464,  -- Mind you, this isn't the only variety of stone you'll be needing. There exists another: stratum abyssite.
        WHEREAS_THE_VOIDSTONE_SERVES_AS_A_POWER_SOURCE                        = 15465,  -- Whereas the voidstone serves as a power source, acting as a compass for channeling that power is stratum abyssite. Only by using the two in conjunction can we achieve our objectives.
        ARE_YOU_FAMILIAR_WITH_VOIDDUST_PUT_SIMPLY_IT                          = 15466,  -- Are you familiar with voiddust? Put simply, it is a granular substance from which voidstones may be fabricated.
        AS_I_EXPLAINED_SIGNIFICANT_TIME_IS_REQUIRED_TO                        = 15467,  -- As I explained, significant time is required to produce a voidstone from scratch. Provide me with voiddust, however, and I can fashion a stone for you in short order.
        THE_SAME_COMRADES_OF_OURS_WHO_STOCK_ASCENT                            = 15468,  -- The same comrades of ours who stock ascent items may also furnish you with voiddust. Why do they not fabricate the stones themselves, or deliver the dust directly to me? Shush! The Voidwatch works in mysterious ways, and it would behoove you to inquire no further.
        AT_ANY_RATE_SHOULD_YOU_MANAGE_TO_OBTAIN                               = 15469,  -- At any rate, should you manage to obtain any voiddust in your travels, you need only return here and trade it to me. Simple enough, wouldn't you say?
        FURTHERMORE_THIS_PARTICULAR_VARIETY_OF_ABYSSITE_IS_KNOWN              = 15470,  -- Furthermore, this particular variety of abyssite is known to absorb the energy released by felled Voidwalkers. Not any of the creatures, mind you, but only those drawn to planar rifts.
        BASED_ON_THE_EVOLUTIONARY_STATE_OF_YOUR_STRATUM                       = 15471,  -- Based on the evolutionary state of your stratum abyssite, the Voidwatch will direct you to a suitable operation area.
        IF_YOU_WISH_TO_HAVE_YOUR_STONE_ANALYZED                               = 15472,  -- If you wish to have your stone analyzed, simply present it to an atma refiner.
        PLANAR_RIFTS_WEAK_POINTS_IN_THE_FABRIC_OF                             = 15473,  -- Planar rifts--weak points in the fabric of space--have manifested across the land. The Voidwalker hordes roam beyond, unchecked and ever seeking to enter and plunge Vana'diel into chaos.
        BY_INVOKING_THE_POWER_OF_STRATUM_ABYSSITE_IT                          = 15474,  -- By invoking the power of stratum abyssite, it is possible to battle the fell creatures as a Voidwatcher--a defender of our dimension.
        THOSE_ALSO_POSSESSED_OF_A_VOIDSTONE_WILL_FIND                         = 15475,  -- Those also possessed of a voidstone will find their Voidwatcher experience greatly enhanced.
        ALONE_HOWEVER_STRATUM_ABYSSITE_SERVES_NO_PURPOSE_ONLY                 = 15476,  -- Alone, however, stratum abyssite serves no purpose; only when used in conjunction with a voidstone can its powers be unleashed.
        HENCE_AT_LEAST_ONE_MEMBER_OF_YOUR_SQUAD                               = 15477,  -- Hence, at least one member of your squad--be it party or alliance--must possess a voidstone in order to arrange a confrontation with a Voidwalker.
        KEEP_THIS_FACT_IN_MIND_AT_ALL_TIMES                                   = 15478,  -- Keep this fact in mind at all times.
        IT_IS_NOT_KNOWN_WHEN_THE_PLANAR_RIFTS                                 = 15479,  -- It is not known when the planar rifts first manifested. Some say they've always been there, while others claim recent events have triggered their appearance.
        IF_ONLY_WE_COULD_RETURN_TO_THE_PAST                                   = 15480,  -- If only we could return to the past, perhaps we could shed some light upon this mystery...
        OBTAINABLE_BY_DEFEATING_VOIDWALKERS_CRUOR_IS_AN_ENERGY                = 15481,  -- Obtainable by defeating Voidwalkers, cruor is an energy source that takes the form of shiny red granules.
        WHILE_APPEARING_TO_BE_SOME_MANNER_OF_MINERAL                          = 15482,  -- While appearing to be some manner of mineral, detailed analysis has revealed that cruor is in fact organic.
        AS_FAR_AS_OUR_RESEARCHERS_CAN_TELL_HOWEVER                            = 15483,  -- As far as our researchers can tell, however, it's inanimate like most well-behaved plants. There's no fear of cruor suddenly springing to life in your palms.
        BEING_SUPREMELY_PLEASING_TO_THE_EYES_CRUOR_MIGHT                      = 15484,  -- Being supremely pleasing to the eyes, cruor might have adorned the display cases of many a jewelry shop during peacetime. Unfortunately, the age demands that its unique properties be put to more practical uses.
        NAMELY_THE_INFUSION_AND_ENRICHMENT_OF_ATMACITE_IF                     = 15485,  -- Namely, the infusion and enrichment of atmacite. If you wish to learn about these two processes, you need but ask an atmacite refiner, our experts on such matters.
        AS_CRUOR_IS_A_VITAL_ASPECT_OF_OUR                                     = 15486,  -- As cruor is a vital aspect of our operations, the Voidwatch is always looking to procure more. Should you have any excess cruor, we would be glad to take it off your hands and offer you useful items in exchange.
        ABYSSITE_IS_THE_NAME_GIVEN_TO_A_MYSTERIOUS                            = 15487,  -- Abyssite is the name given to a mysterious stone that assumes various forms and colors, the roles they serve likewise manifold in nature.
        OF_THE_COPIOUS_VARIETIES_THUS_FAR_DISCOVERED_THERE                    = 15488,  -- Of the copious varieties thus far discovered, there exist those called periapt--lucky charms that grant myriad beneficial effects ranging from improved vitality to general upturns in fortune.
        DEFEATING_A_VOIDWALKER_IS_KNOWN_TO_YIELD_PERIAPT                      = 15489,  -- Defeating a Voidwalker is known to yield periapt on very rare occasions. Serve the Voidwatch earnestly, however, and you will surely have one to call your own.
        SELECT_WHERE_VOIDSTONES_WILL_BE_CONSUMED_FROM                         = 15490,  -- Select where voidstones will be consumed from.
        SET_TO_WHICH_KEY_ITEMS_STOCK                                          = 15491,  -- Set to which? Key items. Stock.
        VOIDSTONES_WILL_NOW_BE_TAKEN_FROM                                     = 15492,  -- Voidstones will now be taken from [your key items/the stock].
        BROUGHT_ME_VOIDDUST_HAVE_YOU_JUST_ONE_MOMENT                          = 15493,  -- Brought me voiddust, have you? Just one moment, now... And here is your voidstone! Take it and use it well.
        BROUGHT_ME_VOIDDUST_HAVE_YOU_JUST_ONE_MOMENT_2                        = 15494,  -- Brought me voiddust, have you? Just one moment, now... And here are your voidstones! Take them and use them well.
